const BANK = [
// VALUES & SOCIETY
{cat:"Values & Society",q:"Which of the following best describes a fundamental British value?",o:["Loyalty to a single political party","Tolerance and respect for others","Speaking only English in public","Practising Christianity"],a:1,exp:"The fundamental values include democracy, rule of law, individual liberty, and mutual respect and tolerance for those with different faiths and beliefs.",variants:[{q:"Which is recognised as a core value of British life?",o:["Mandatory church attendance","Mutual respect and tolerance for others","Strict obedience to one political party","English-only public communication"],a:1}]},
{cat:"Values & Society",q:"What does 'rule of law' mean in the UK?",o:["The government can make any law it wishes","Everyone — including the government — must obey the law","Laws are made by judges rather than Parliament","The police decide which laws are enforced"],a:1,exp:"The rule of law means no one is above the law, including the government. Disputes are settled by independent courts.",variants:[{q:"Under the principle of rule of law, who must follow the law?",o:["Only ordinary citizens","Everyone, including ministers and the monarch","Only those without political office","Only those convicted of crimes"],a:1}]},
{cat:"Values & Society",q:"Which of these is NOT a fundamental principle of British life?",o:["Democracy","Rule of law","Forced religion","Individual liberty"],a:2,exp:"The four fundamental principles are: democracy, rule of law, individual liberty, and mutual respect and tolerance. Religious observance is a personal choice.",variants:[{q:"Which one is NOT one of the fundamental British values?",o:["Tolerance","Rule of law","Compulsory religious practice","Democracy"],a:2}]},
{cat:"Values & Society",q:"What does 'democracy' mean in the UK?",o:["The monarch makes all decisions","Citizens elect representatives to govern","All laws decided by public referendum","Only property owners may vote"],a:1,exp:"Democracy means citizens choose their representatives through free and fair elections. The UK is a representative democracy.",variants:[{q:"How is democracy practised in the UK?",o:["Through hereditary rule by the monarch","By electing representatives in free elections","Only through nationwide referendums","Through unelected committees of judges"],a:1}]},
{cat:"Values & Society",q:"Which organisation oversees UK elections to ensure they are fair?",o:["The Home Office","The Electoral Commission","The House of Lords","The Boundary Commission"],a:1,exp:"The Electoral Commission is the independent body responsible for overseeing elections and referendums and regulating party finances.",variants:[{q:"Which independent body regulates UK elections and party finances?",o:["The Boundary Commission","The Cabinet Office","The Electoral Commission","The Office for National Statistics"],a:2}]},
{cat:"Values & Society",q:"What does freedom of speech mean in the UK?",o:["You can say absolutely anything without consequence","You can express opinions freely within the law","Only journalists have freedom of speech","Freedom of speech only applies in Parliament"],a:1,exp:"Freedom of speech means expressing opinions without government censorship. It has legal limits — for example, inciting hatred is illegal."},
{cat:"Values & Society",q:"Jury service is an obligation for eligible UK citizens. Who qualifies?",o:["Homeowners aged 18 or over only","Adults with no criminal record only","Citizens aged 18–70 on the electoral roll","Any UK adult aged 25 or older"],a:2,exp:"Any UK citizen aged 18--70 who is registered to vote can be called for jury service. Failing to respond is a criminal offence.",variants:[{q:"Who can be called for jury service in the UK?",o:["Only adults aged 21 and over","Citizens 18–70 registered to vote","Anyone aged 16 or older","Only homeowners with no criminal record"],a:1}]},
{cat:"Values & Society",q:"What is the role of the civil service?",o:["Campaigns for the ruling political party","Implements policy impartially for any elected government","Chooses who will be the next Prime Minister","Writes and passes legislation in Parliament"],a:1,exp:"The civil service is politically neutral and implements government policy. Civil servants serve whichever party forms the government."},
{cat:"Values & Society",q:"Which of the following is a right AND responsibility of a UK citizen?",o:["To demand benefits from the state","To vote in elections and serve on a jury if called","To fly the Union Flag at all times","To speak only English in public"],a:1,exp:"Voting and jury service are both rights and responsibilities. The others are not legal obligations."},
{cat:"Values & Society",q:"What does 'individual liberty' mean as a British value?",o:["Everyone must obey the government without question","People are free to live as they choose within the law","Only British-born citizens have full freedom","Liberty is limited to property owners"],a:1,exp:"Individual liberty means people can make their own choices and live as they wish, as long as they stay within the law and respect others' rights."},

// BRITISH HISTORY
{cat:"British History",q:"Who defeated Harold II at the Battle of Hastings in 1066?",o:["Richard the Lionheart of England","King Canute of Denmark","William, Duke of Normandy","Harald Hardrada of Norway"],a:2,exp:"William, Duke of Normandy, won the Battle of Hastings in October 1066 and became William I — William the Conqueror.",variants:[{q:"Who became king of England after winning the Battle of Hastings?",o:["Harald Hardrada","Edward the Confessor","William the Conqueror","Canute the Great"],a:2}]},
{cat:"British History",q:"Which king signed Magna Carta in 1215?",o:["Henry VIII","King John","Richard II","Henry II"],a:1,exp:"King John signed Magna Carta at Runnymede in 1215 under pressure from rebellious barons. It limited royal power and established the rule of law.",variants:[{q:"Magna Carta was sealed at Runnymede by which monarch?",o:["Henry III","King John","Edward I","Richard I"],a:1}]},
{cat:"British History",q:"What was the significance of the Glorious Revolution of 1688?",o:["England became a republic for good","Parliament's power over the monarch was affirmed","Scotland and England were formally unified","The Church of England was abolished"],a:1,exp:"The Glorious Revolution brought William of Orange to the throne and led to the Bill of Rights (1689), establishing Parliament's supremacy."},
{cat:"British History",q:"In which century did the Industrial Revolution begin in Britain?",o:["16th century","17th century","18th century","19th century"],a:2,exp:"The Industrial Revolution began in Britain in the 18th century. Britain was the first industrialised nation, driven by textile mills, steam power and iron production.",variants:[{q:"Britain was the first country to industrialise — when did this begin?",o:["The 1500s","The 1700s","The 1800s","The 1600s"],a:1}]},
{cat:"British History",q:"What was the main cause of the English Civil War (1642--51)?",o:["A religious dispute between Protestants and Catholics","Conflict between Charles I and Parliament over the limits of royal power","Scotland's attempt to invade England","France's invasion of southern England"],a:1,exp:"The Civil War was primarily about whether the King or Parliament held ultimate authority. Charles I believed in the divine right of kings."},
{cat:"British History",q:"What happened to King Charles I after the English Civil War?",o:["He was exiled to France","He was executed in 1649","He was imprisoned for life","He abdicated and fled to Scotland"],a:1,exp:"Charles I was tried by Parliament for treason and executed in January 1649. England became a republic (Commonwealth) under Oliver Cromwell."},
{cat:"British History",q:"The Acts of Union 1707 united which two countries?",o:["England and Ireland","England and Wales","England and Scotland","Great Britain and Ireland"],a:2,exp:"The Acts of Union 1707 joined England and Scotland to form the Kingdom of Great Britain. Wales had been incorporated into England by earlier legislation.",variants:[{q:"What did the 1707 Acts of Union create?",o:["The United Kingdom of Great Britain and Ireland","The Kingdom of Great Britain (England and Scotland)","A union between England and Wales","A union between Britain and France"],a:1}]},
{cat:"British History",q:"When was the current Union Flag created?",o:["1606","1707","1801","1850"],a:2,exp:"The current Union Flag was created in 1801 when Ireland joined Great Britain, adding St Patrick's Cross to the design."},
{cat:"British History",q:"What major social reform occurred in Britain in 1948?",o:["The founding of NATO","The creation of the NHS","The Festival of Britain","Women gaining equal voting rights"],a:1,exp:"The National Health Service (NHS) was founded in 1948 by the post-war Labour government — one of the greatest social reforms in British history.",variants:[{q:"Which institution was established in Britain in 1948?",o:["The BBC","The National Health Service","The Bank of England","The United Nations"],a:1}]},
{cat:"British History",q:"What was the suffragette movement?",o:["A campaign for workers' rights","A campaign for women's right to vote","A campaign to extend voting to working-class men","An early environmental movement"],a:1,exp:"Suffragettes campaigned militantly for women's voting rights. Key figures include Emmeline Pankhurst and her daughters Sylvia and Christabel."},
{cat:"British History",q:"In what year did women over 30 first receive the right to vote?",o:["1903","1911","1918","1928"],a:2,exp:"The Representation of the People Act 1918 gave women over 30 with property qualifications the right to vote. Equal voting rights came in 1928.",variants:[{q:"When were women over 30 (with property qualifications) first allowed to vote in the UK?",o:["1918","1928","1908","1900"],a:0}]},
{cat:"British History",q:"Which battle in 1415 saw Henry V defeat France?",o:["Battle of Bosworth Field","Battle of Agincourt","Battle of Crécy","Battle of Poitiers"],a:1,exp:"The Battle of Agincourt (1415) was a famous English victory during the Hundred Years War, celebrated in Shakespeare's 'Henry V'."},
{cat:"British History",q:"Who was the first Tudor monarch?",o:["Henry VIII","Henry VII","Edward VI","Elizabeth I"],a:1,exp:"Henry VII became the first Tudor king after defeating Richard III at the Battle of Bosworth Field in 1485, ending the Wars of the Roses."},
{cat:"British History",q:"The Domesday Book was commissioned by which king?",o:["Harold II","Edward the Confessor","William I","Henry I"],a:2,exp:"William I commissioned the Domesday Book in 1085--86 — a comprehensive survey of England to assess land ownership and tax obligations."},
{cat:"British History",q:"Who led the Parliamentarians during the English Civil War?",o:["John Locke","Oliver Cromwell","Thomas Cromwell","Duke of Marlborough"],a:1,exp:"Oliver Cromwell was the leading Parliamentary military commander and later became Lord Protector after the execution of Charles I."},
{cat:"British History",q:"Who wrote the plays 'Hamlet', 'Macbeth' and 'A Midsummer Night's Dream'?",o:["Geoffrey Chaucer","Christopher Marlowe","William Shakespeare","John Milton"],a:2,exp:"William Shakespeare (1564--1616) is widely regarded as the greatest writer in the English language. He was born in Stratford-upon-Avon."},
{cat:"British History",q:"Which English queen reigned for over 70 years until 2022?",o:["Victoria","Elizabeth II","Elizabeth I","Mary I"],a:1,exp:"Queen Elizabeth II reigned from 1952 until her death in 2022 — over 70 years — making her the longest-reigning British monarch in history."},
{cat:"British History",q:"What century did the Great Fire of London occur?",o:["15th century","16th century","17th century","18th century"],a:2,exp:"The Great Fire of London occurred in September 1666 — the 17th century. Sir Christopher Wren oversaw much of the rebuilding, including St Paul's Cathedral."},
{cat:"British History",q:"The Magna Carta (1215) primarily established what?",o:["A full written constitution for England","That the king was subject to the rule of law","Free elections for all male citizens","The Church's independence from the state"],a:1,exp:"Magna Carta established that the king was subject to the rule of law — a cornerstone of the British constitution. It did not create a full constitution or free elections."},
{cat:"British History",q:"Which battle ended the Wars of the Roses in 1485?",o:["Battle of Agincourt","Battle of Naseby","Battle of Bosworth Field","Battle of Flodden"],a:2,exp:"The Battle of Bosworth Field (1485) ended the Wars of the Roses when Henry Tudor defeated Richard III, becoming Henry VII — the first Tudor king."},

// A MODERN SOCIETY
{cat:"A Modern Society",q:"Which of the following is true about the BBC?",o:["A private company owned by shareholders","Funded entirely from general taxation","A public broadcaster funded by the licence fee","An online-only streaming broadcaster"],a:2,exp:"The BBC is a public broadcaster funded primarily by the TV licence fee. It was established by Royal Charter and is editorially independent of the government."},
{cat:"A Modern Society",q:"What is a local council?",o:["A committee advising the Prime Minister","An elected body providing local services","A branch of the NHS","A community group with no official power"],a:1,exp:"Local councils are elected bodies responsible for local services including refuse collection, parks, planning, and local roads."},
{cat:"A Modern Society",q:"The 2012 Olympic Games were held in which UK city?",o:["Manchester","Birmingham","London","Edinburgh"],a:2,exp:"The 2012 Summer Olympics were held in London at the Olympic Park in Stratford, east London — widely regarded as a great success.",variants:[{q:"Which UK city hosted the Summer Olympics in 2012?",o:["Birmingham","Glasgow","London","Manchester"],a:2}]},
{cat:"A Modern Society",q:"Who was Isaac Newton?",o:["A Scottish philosopher who wrote about democracy","An English scientist known for laws of motion and gravity","A Welsh mathematician who invented calculus alone","An Irish physicist who discovered electricity"],a:1,exp:"Isaac Newton (1643--1727) was born in Lincolnshire. He formulated laws of motion and universal gravitation and is considered one of history's most influential scientists."},
{cat:"A Modern Society",q:"What does the term 'multicultural society' describe?",o:["A policy requiring one national culture","Co-existence of many different cultures and ethnicities","A system where each ethnic group lives separately","An EU immigration framework"],a:1,exp:"A multicultural society is one where people of different ethnic, cultural, and religious backgrounds co-exist. The UK is one of the world's most diverse societies."},
{cat:"A Modern Society",q:"What is the National Living Wage?",o:["A recommended pay guide for large businesses","The legal minimum hourly pay for workers 23+","A weekly benefit paid to low-income families","The national average wage across the UK"],a:1,exp:"The National Living Wage is the legal minimum wage for workers aged 23 and over. Younger workers have separate minimum wage rates."},
{cat:"A Modern Society",q:"Glastonbury, held annually in Somerset, is best known as what kind of event?",o:["A Highland games festival","A music and performing arts festival","A Welsh literary festival","A royal flower show"],a:1,exp:"Glastonbury is a major outdoor music and performing arts festival held in Somerset, England. It is one of the largest and most famous music festivals in the world."},
{cat:"A Modern Society",q:"What percentage of people in England and Wales identified as Christian in the 2011 Census?",o:["About 30%","About 59%","About 70%","About 45%"],a:1,exp:"In the 2011 Census, 59% identified as Christian. This fell to 46% in the 2021 Census. The Life in the UK handbook references the 2011 figure."},

// GOVERNMENT & LAW
{cat:"Government & Law",q:"How is the Prime Minister chosen?",o:["Directly elected by the general public","Chosen by vote of the House of Lords","Leader of the party with most Commons seats","Appointed by the monarch independently"],a:2,exp:"The PM is the leader of the party winning the most Commons seats, then formally appointed by the monarch.",variants:[{q:"Who becomes Prime Minister after a general election?",o:["The candidate with the most votes nationally","The leader of the party with most seats in the Commons","The most senior member of the House of Lords","Whoever the monarch personally selects"],a:1}]},
{cat:"Government & Law",q:"What is the role of the House of Lords?",o:["The most powerful chamber — it overrides the Commons","It scrutinises and can amend or delay Commons legislation","It elects the Prime Minister","It controls the national budget"],a:1,exp:"The Lords reviews legislation from the Commons and can suggest amendments or delay (but not permanently block) bills. The Commons has ultimate authority."},
{cat:"Government & Law",q:"What is the maximum term of a UK Parliament?",o:["4 years","5 years","6 years","3 years"],a:1,exp:"A general election must take place within 5 years. The Prime Minister may call an earlier election.",variants:[{q:"How often must a UK general election be held at the latest?",o:["Every 3 years","Every 4 years","Every 5 years","Every 7 years"],a:2}]},
{cat:"Government & Law",q:"Which is the highest court in the UK?",o:["The Court of Appeal","The High Court","The Crown Court","The Supreme Court"],a:3,exp:"The UK Supreme Court, established in 2009, is the highest court of appeal. It replaced the Appellate Committee of the House of Lords.",variants:[{q:"What is the final court of appeal in the UK?",o:["The High Court","The Court of Appeal","The Supreme Court","The Crown Court"],a:2}]},
{cat:"Government & Law",q:"What voting system is used for UK general elections?",o:["Proportional representation","Alternative vote","First past the post","Single transferable vote"],a:2,exp:"UK general elections use first past the post (FPTP) — the candidate with the most votes in each constituency wins, even without a majority.",variants:[{q:"How are MPs elected to the House of Commons?",o:["By proportional representation","By single transferable vote","By first past the post","By alternative vote"],a:2}]},
{cat:"Government & Law",q:"Who appoints judges in the UK?",o:["The Prime Minister directly chooses them","The monarch, on advice of the Judicial Appointments Commission","Elected by a vote of both Houses of Parliament","The Lord Chief Justice chooses them alone"],a:1,exp:"Judges are appointed by the monarch on advice of the Judicial Appointments Commission — an independent body ensuring judicial independence from politicians."},
{cat:"Government & Law",q:"What body is responsible for making UK-wide laws?",o:["The Scottish Parliament","The UK Parliament at Westminster","The European Union","The Supreme Court"],a:1,exp:"The UK Parliament at Westminster is sovereign and legislates for the entire UK. Devolved assemblies handle devolved matters only."},
{cat:"Government & Law",q:"What is the 'Speaker' of the House of Commons?",o:["The Prime Minister's spokesperson","The MP who chairs debates and maintains order in the Commons","The leader of the opposition","The minister who reads out government statements"],a:1,exp:"The Speaker is an MP elected by fellow MPs to chair debates impartially. Once elected, they give up party affiliation."},
{cat:"Government & Law",q:"What does 'innocent until proven guilty' mean?",o:["Only the wealthy can afford to prove innocence","The prosecution must prove guilt, not the defendant","A judge must always believe what the defendant says","The police decide guilt before any trial takes place"],a:1,exp:"This is the presumption of innocence. The burden of proof lies with the prosecution to prove guilt beyond reasonable doubt."},
{cat:"Government & Law",q:"What is the role of a jury in a Crown Court trial?",o:["To decide the sentence","To hear evidence and decide guilty or not guilty","To assist the judge in writing the law","To prosecute the defendant"],a:1,exp:"A jury of 12 members of the public decides the verdict. The judge decides the sentence if the defendant is found guilty."},
{cat:"Government & Law",q:"What are the devolved governments of the UK?",o:["City councils of London, Manchester, Birmingham","The Scottish Parliament, Welsh Senedd and NI Assembly","Regional development agencies run by Whitehall","County councils across the whole of England"],a:1,exp:"Devolved power has been granted to the Scottish Parliament, Welsh Senedd, and Northern Ireland Assembly. England has no separate parliament."},
{cat:"Government & Law",q:"What is an MP's 'surgery'?",o:["Free medical consultations for constituents","Regular meetings where MPs hear constituents' concerns","Party membership recruitment sessions","Training sessions for new MPs"],a:1,exp:"MPs hold constituency surgeries — meetings where local people raise concerns about issues such as housing, benefits, or immigration."},
{cat:"Government & Law",q:"What is council tax used to fund?",o:["National defence and the armed forces","Local services like rubbish, schools and roads","The NHS and hospitals exclusively","Central government departments in Whitehall"],a:1,exp:"Council tax funds local services including refuse collection, libraries, parks, local roads, and contributes to local police and fire services."},
{cat:"Government & Law",q:"What is Hansard?",o:["The official record of Parliamentary debates","A UK political journal","The government's annual budget","A register of lobbyists"],a:0,exp:"Hansard is the verbatim official record of all debates and proceedings in both Houses of Parliament, published online."},
{cat:"Government & Law",q:"What is the role of the Leader of the Opposition?",o:["Supports and votes for government legislation","Leads the largest non-government party and scrutinises the PM","Chairs debate in the House of Commons daily","Gives confidential advice to the monarch"],a:1,exp:"The Leader of the Opposition leads a 'shadow cabinet' that scrutinises the government and presents an alternative programme, notably in Prime Minister's Questions."},
{cat:"Government & Law",q:"What is a 'by-election'?",o:["An election to choose a local council leader","An election when an MP's seat becomes vacant between general elections","A second round if no candidate wins outright","An election in Scotland or Wales only"],a:1,exp:"A by-election is held when an MP vacates their seat between general elections due to death, resignation, or disqualification."},

// NATIONS & SYMBOLS
{cat:"Nations & Symbols",q:"What is the national flower of England?",o:["Daffodil","Thistle","Rose","Shamrock"],a:2,exp:"The rose is the national flower of England. The red rose is also the emblem of the Labour Party.",variants:[{q:"Which flower is the national symbol of England?",o:["Thistle","Daffodil","Rose","Shamrock"],a:2}]},
{cat:"Nations & Symbols",q:"What is the national flower of Scotland?",o:["Heather","Thistle","Bluebell","Primrose"],a:1,exp:"The thistle has been Scotland's emblem since the reign of Alexander III (1249--1286).",variants:[{q:"Which plant is Scotland's national emblem?",o:["Heather","Thistle","Rose","Bluebell"],a:1}]},
{cat:"Nations & Symbols",q:"What is the national flower of Wales?",o:["Leek","Shamrock","Daffodil","Rose"],a:2,exp:"The daffodil is the national flower of Wales. The leek is the national emblem — both symbols are associated with Wales."},
{cat:"Nations & Symbols",q:"What does the Union Flag combine?",o:["The flags of England, Scotland and Wales","The crosses of St George, St Andrew and St Patrick","The symbols of the monarchy, Parliament and Church","The flags of all Commonwealth nations"],a:1,exp:"The Union Flag combines St George's Cross (England), St Andrew's Cross (Scotland) and St Patrick's Cross (Ireland). Wales is not separately represented."},
{cat:"Nations & Symbols",q:"Which language is spoken in Wales alongside English?",o:["Gaelic","Cornish","Welsh","Manx"],a:2,exp:"Welsh (Cymraeg) is an official language in Wales alongside English. About 30% of Welsh people speak Welsh."},
{cat:"Nations & Symbols",q:"What does the dragon on the Welsh flag represent?",o:["It marks the Roman occupation of Wales","An ancient symbol of Wales from myth and legend","It was added to honour King Henry VIII","It represents Wales's industrial heritage"],a:1,exp:"The red dragon (Y Ddraig Goch) is an ancient symbol of Wales. The current flag became official in 1959."},
{cat:"Nations & Symbols",q:"What is the Eisteddfod?",o:["A Scottish Highland games event","A Welsh festival of music, literature and the arts","An English folk dance competition","A Northern Irish cultural festival"],a:1,exp:"The Eisteddfod is a Welsh cultural festival primarily in the Welsh language. The National Eisteddfod alternates between north and south Wales."},
{cat:"Nations & Symbols",q:"What instrument is traditionally associated with Welsh culture?",o:["Bagpipes","The fiddle","The harp","The lute"],a:2,exp:"The harp is closely associated with Wales. The national eisteddfod prominently features the harp. Wales is sometimes called 'the land of song'."},
{cat:"Nations & Symbols",q:"What flower is worn on Remembrance Day?",o:["White lily","Red poppy","Bluebell","Daffodil"],a:1,exp:"The red poppy is worn around Remembrance Day (11 November). The tradition began after World War I, inspired by the poem 'In Flanders Fields'."},
{cat:"Nations & Symbols",q:"What is the name of the devolved parliament of Wales?",o:["The Welsh National Assembly","The Welsh Parliament (Senedd Cymru)","The Welsh Congress of Ministers","The Cymru National Council"],a:1,exp:"The Welsh Parliament is officially the Senedd Cymru. Previously called the National Assembly for Wales, it has powers over health, education and other devolved matters."},

// EVERYDAY LIFE
{cat:"Everyday Life",q:"What is the NHS?",o:["A private health insurance scheme","The National Health Service — free at the point of use","A network of private paying hospitals","A charitable organisation running hospitals"],a:1,exp:"The NHS was founded in 1948 and provides healthcare free at the point of use for all UK residents, funded by taxation and National Insurance."},
{cat:"Everyday Life",q:"At what age can a person in England marry without parental consent?",o:["16","17","18","21"],a:2,exp:"The legal marriage age without parental consent is 18 in England, Wales and Northern Ireland. Scotland introduced this change in 2023."},
{cat:"Everyday Life",q:"What is a National Insurance number?",o:["A reference number used to access NHS services","A unique number tracking your tax and NI record","An identifier required in order to vote","Your personal bank account reference"],a:1,exp:"A National Insurance number is a unique reference ensuring your tax and NI contributions are recorded. It qualifies you for benefits and the state pension.",variants:[{q:"What is the purpose of your National Insurance (NI) number?",o:["To register on the electoral roll","To track your tax and NI contributions","To access NHS healthcare","To open a UK bank account"],a:1}]},
{cat:"Everyday Life",q:"What is the minimum legal requirement for UK car insurance?",o:["Comprehensive insurance","Third-party insurance","Fully comprehensive with breakdown cover","Employer's liability insurance"],a:1,exp:"Drivers are legally required to have at least third-party insurance. Driving without insurance is a criminal offence."},
{cat:"Everyday Life",q:"What is the minimum school participation age in England?",o:["15","16","17","18"],a:3,exp:"Young people in England must stay in education or training until 18. This could be school, college, apprenticeships, or part-time training alongside work."},
{cat:"Everyday Life",q:"What is a GP?",o:["A Government Prescriptions service","A General Practitioner — a local family doctor","A Grade Points academic system","A Government Pension scheme"],a:1,exp:"A GP (General Practitioner) is a local family doctor providing primary care, referrals to specialists, and prescriptions."},
{cat:"Everyday Life",q:"What is the purpose of a TV licence?",o:["A tax on owning any electronic device","Required to watch live TV or use BBC iPlayer","A voluntary subscription for ITV content","A permit needed to record any TV programmes"],a:1,exp:"A TV licence is required to watch any live television or use BBC iPlayer. It funds the BBC's public broadcasting services."},
{cat:"Everyday Life",q:"How old must you be to buy alcohol in the UK?",o:["16","17","18","21"],a:2,exp:"You must be 18 or over to buy alcohol. It is also an offence to buy alcohol for someone under 18."},
{cat:"Everyday Life",q:"What does 999 connect you to?",o:["The NHS non-emergency health line","The police non-emergency contact line","Emergency services: police, fire, ambulance","The coastguard and sea rescue only"],a:2,exp:"999 is the emergency services number. For non-emergency police use 101; for non-emergency NHS advice use 111."},
{cat:"Everyday Life",q:"What is the 'right to buy' scheme?",o:["The right to buy shares in the stock market","A scheme letting council house tenants buy their home at a discount","A consumer right to return goods within 30 days","The right to buy Crown land"],a:1,exp:"Right to Buy, introduced in 1980 under Thatcher, allowed council tenants to buy their homes at a significant discount, dramatically increasing home ownership."},
{cat:"Everyday Life",q:"What does 'GCSE' stand for?",o:["General Certificate of Secondary Education","General Certificate of School Examination","Government-Certified Secondary Education","General Curriculum Standard Examination"],a:0,exp:"GCSE stands for General Certificate of Secondary Education — exams taken by students in England, Wales and Northern Ireland at around age 16."},
{cat:"Everyday Life",q:"What does Ofsted do?",o:["The Office for Standards in Education — inspects schools","Regulates UK banks and financial services","Oversees the government's health department","Supports children who are in council care"],a:0,exp:"Ofsted (Office for Standards in Education) inspects schools and other education providers in England, rating them Outstanding, Good, Requires Improvement or Inadequate."},

// UK & WORLD
{cat:"UK & World",q:"What is the Commonwealth?",o:["A military alliance of nations led by the UK","A trading bloc set up to replace EU membership","A voluntary association of 56 mostly ex-British countries","Countries which still use the pound sterling"],a:2,exp:"The Commonwealth is a voluntary association of 56 independent countries. Members cooperate on trade, development and democracy but have no formal obligations."},
{cat:"UK & World",q:"The UK is a permanent member of which global body with a veto?",o:["The G7","The NATO security committee","The UN Security Council","The World Trade Organisation"],a:2,exp:"The UK is one of five permanent UN Security Council members (with the USA, Russia, China and France), each holding veto power."},
{cat:"UK & World",q:"What does NATO stand for?",o:["North American Treaty Organisation","North Atlantic Treaty Organisation","National Alliance of Treaty Obligations","Nordic and Atlantic Trade Organisation"],a:1,exp:"NATO stands for North Atlantic Treaty Organisation. The UK is a founding member. Under Article 5, an attack on one member is treated as an attack on all."},
{cat:"UK & World",q:"When did the UK formally leave the European Union?",o:["January 2019","January 2020","June 2016","December 2020"],a:1,exp:"The UK formally left the EU on 31 January 2020, following the June 2016 referendum result (52% voted to leave). The transition period ended 31 December 2020."},
{cat:"UK & World",q:"What currency does the UK use?",o:["The euro","The pound sterling","The US dollar","The crown"],a:1,exp:"The UK uses the pound sterling (£, GBP). It did not adopt the euro when it was introduced."},
{cat:"UK & World",q:"What is the G7?",o:["A group of 7 of the world's largest economies","A NATO sub-committee","A UN Security Council working group","A Commonwealth trade body"],a:0,exp:"The G7 is a group of seven major advanced economies: the UK, USA, Canada, France, Germany, Italy, and Japan. The EU also participates."},
{cat:"UK & World",q:"What did the UK help found after World War II to promote peace?",o:["The EU","The United Nations","The Commonwealth","NATO"],a:1,exp:"The UK was a founding member of the United Nations, established in 1945 to maintain international peace and security."},
{cat:"UK & World",q:"The Falkland Islands are an overseas territory of which country?",o:["Australia","New Zealand","The United Kingdom","Canada"],a:2,exp:"The Falkland Islands are a British Overseas Territory. The UK and Argentina fought a war over them in 1982, which the UK won."},
{cat:"UK & World",q:"What does 'the special relationship' refer to?",o:["The relationship between England and Scotland","Close diplomatic, military and cultural ties between the UK and the USA","The UK's trading relationship with the Commonwealth","The UK's unique membership of NATO and the UN"],a:1,exp:"The 'special relationship' describes the exceptionally close ties between the UK and the United States. The term was popularised by Winston Churchill."},

// ── BRITISH HISTORY (harder) ──────────────────────────────
{cat:"British History",q:"In what year was the Magna Carta signed?",o:["1066","1215","1265","1314"],a:1,exp:"Magna Carta was signed by King John in 1215 at Runnymede, on the banks of the River Thames."},
{cat:"British History",q:"What was the 'Black Death'?",o:["A volcanic eruption that devastated Northern England","A bubonic plague that killed a third of the UK in the 14th century","A series of long famines in medieval Ireland","A name given to the thick smogs of industrial London"],a:1,exp:"The Black Death (bubonic plague) arrived in England in 1348 and killed around a third of the population. It had enormous social and economic consequences."},
{cat:"British History",q:"Which monarch established the Church of England by breaking from Rome?",o:["Edward VI","Mary I","Henry VIII","Elizabeth I"],a:2,exp:"Henry VIII broke from the Roman Catholic Church in the 1530s, primarily to annul his marriage to Catherine of Aragon. He made himself Supreme Head of the Church of England."},
{cat:"British History",q:"What was the Habeas Corpus Act of 1679?",o:["A law granting married women the right to own property","A law stopping the monarch raising taxes without Parliament","A law requiring a prisoner be brought before a court","A law establishing the Church of England by statute"],a:2,exp:"Habeas Corpus (1679) established that anyone imprisoned must be brought before a court to determine whether their detention is lawful — a fundamental protection against arbitrary imprisonment."},
{cat:"British History",q:"The 'Reformation' in 16th century England primarily involved what?",o:["A sweeping reform of the national voting system","The break from the Roman Catholic Church, creating a Protestant Church","A series of major reforms to Parliament's powers","A reorganisation of the English common law system"],a:1,exp:"The English Reformation was the break from Rome and the Catholic Church, beginning under Henry VIII and continuing under Edward VI and Elizabeth I, establishing Protestantism as England's official religion."},
{cat:"British History",q:"What was the significance of the Battle of Britain in 1940?",o:["Britain invaded France in 1940 to liberate Paris","The RAF defended Britain from the German Luftwaffe's air attack","Britain defeated the German navy in the North Sea","British forces captured Berlin from the Nazis"],a:1,exp:"The Battle of Britain was an air campaign by Nazi Germany to gain air superiority over Britain. The RAF's successful defence prevented a German invasion and is considered a turning point in WW2."},
{cat:"British History",q:"In which year did the First World War end?",o:["1916","1917","1918","1919"],a:2,exp:"World War One ended on 11 November 1918, when an armistice was signed. This date is commemorated annually as Remembrance Day."},
{cat:"British History",q:"Which prime minister led Britain during most of the Second World War?",o:["Neville Chamberlain","Clement Attlee","Anthony Eden","Winston Churchill"],a:3,exp:"Winston Churchill became Prime Minister in May 1940 and led Britain through most of WW2. He is widely regarded as one of the greatest wartime leaders in history."},
{cat:"British History",q:"What did the Beveridge Report of 1942 propose?",o:["A detailed plan for post-war military alliances","A welfare state providing 'cradle to grave' security","The full nationalisation of all British industry","A new written constitution for post-war Britain"],a:1,exp:"The Beveridge Report (1942) proposed a comprehensive welfare state tackling the 'five giants': Want, Disease, Ignorance, Squalor and Idleness. It laid the foundations for the NHS and post-war welfare state."},
{cat:"British History",q:"What was the name of the ship on which the Pilgrim Fathers sailed to America in 1620?",o:["The Golden Hind","The Endeavour","The Mayflower","The Victory"],a:2,exp:"The Mayflower carried the Pilgrim Fathers — English Puritan settlers — from Plymouth to America in 1620, where they founded Plymouth Colony in what is now Massachusetts."},
{cat:"British History",q:"Who was the first Prime Minister of Great Britain?",o:["William Pitt the Younger","Robert Walpole","William Gladstone","Benjamin Disraeli"],a:1,exp:"Robert Walpole is generally regarded as the first Prime Minister, serving from 1721 to 1742 under George I and George II."},
{cat:"British History",q:"The Chartist movement of the 19th century campaigned for what?",o:["The abolition of slavery across the British Empire","Political reform, votes for all men and a secret ballot","Women's right to vote in national elections","The full independence of Scotland from England"],a:1,exp:"The Chartists (1838--1857) were a working-class movement campaigning for democratic reforms: votes for all men, secret ballots, equal constituencies, and payment for MPs."},
{cat:"British History",q:"In which year did women achieve equal voting rights with men in the UK?",o:["1918","1921","1928","1932"],a:2,exp:"The Equal Franchise Act 1928 gave all women over 21 the vote on equal terms with men. Previously (since 1918), only women over 30 who met property qualifications could vote."},
{cat:"British History",q:"What was the significance of the Reform Act 1832?",o:["It abolished the House of Lords","It extended the right to vote to more men and removed 'rotten boroughs'","It gave women the right to vote for the first time","It created the position of Prime Minister"],a:1,exp:"The Great Reform Act 1832 was a landmark law that extended the vote to more middle-class men, redistributed Parliamentary seats from depopulated 'rotten boroughs' to growing industrial cities."},
{cat:"British History",q:"Which explorer, backed by Queen Elizabeth I, circumnavigated the globe between 1577 and 1580?",o:["Walter Raleigh","James Cook","Francis Drake","Humphrey Gilbert"],a:2,exp:"Sir Francis Drake completed the second circumnavigation of the globe (1577--80) and was the first Englishman to do so. He was later vice admiral during the defeat of the Spanish Armada in 1588."},

// ── GOVERNMENT & LAW (harder) ────────────────────────────
{cat:"Government & Law",q:"What is the difference between criminal law and civil law in the UK?",o:["Criminal law covers adults; civil law covers minors only","Criminal law covers offences against society; civil resolves private disputes","Criminal law is English law; civil law is Scottish law","There is no real difference — they use the same courts"],a:1,exp:"Criminal law covers offences against the state (e.g. theft, assault) prosecuted by the Crown. Civil law resolves disputes between individuals or organisations (e.g. contracts, property). They use different courts."},
{cat:"Government & Law",q:"What is the Oath of Allegiance sworn by new citizens?",o:["A promise to obey all UK laws at all times","A pledge of loyalty to the Crown, and to uphold the rights and freedoms of the UK","A commitment to serve in the armed forces if required","An agreement to pay taxes and contribute to society"],a:1,exp:"New citizens swear (or affirm) an Oath of Allegiance to the monarch and a pledge to uphold the democratic values of the UK at a citizenship ceremony."},
{cat:"Government & Law",q:"Which of these is a devolved matter — meaning Scotland, Wales or N. Ireland decide it for themselves?",o:["Foreign policy","Defence","Health","Immigration"],a:2,exp:"Health is a devolved matter. Foreign policy, defence and immigration are reserved to the UK Parliament at Westminster and apply across the whole UK."},
{cat:"Government & Law",q:"What is the purpose of the Human Rights Act 1998?",o:["It created a written constitution for the United Kingdom","It incorporated the European Convention on Human Rights","It abolished the death penalty in peacetime","It established the UK Supreme Court in London"],a:1,exp:"The Human Rights Act 1998 incorporated the European Convention on Human Rights into UK domestic law, allowing people to enforce their Convention rights in UK courts."},
{cat:"Government & Law",q:"What does 'proportional representation' mean?",o:["One MP per constituency regardless of population","Parties receive seats roughly in proportion to their share of votes","Only the top two candidates go to a run-off vote","Voters rank candidates in order of preference"],a:1,exp:"Under proportional representation, parties win seats in rough proportion to the votes they receive nationally. This contrasts with first past the post, used in UK general elections."},
{cat:"Government & Law",q:"Who is the head of state of the United Kingdom?",o:["The Prime Minister","The Lord Chancellor","The monarch","The Speaker of the House of Commons"],a:2,exp:"The monarch is the UK's head of state. The Prime Minister is the head of government. Currently King Charles III is the head of state."},
{cat:"Government & Law",q:"What is a 'free press' and why is it important in the UK?",o:["Newspapers distributed free of charge to the public","Media independent of government — a check on power","A press regulated entirely by the government itself","State-funded and state-controlled journalism"],a:1,exp:"A free press means the media can report and comment without government censorship or control. It is considered essential to democracy as it holds the government and powerful institutions to account."},
{cat:"Government & Law",q:"What is 'Prime Minister's Questions' (PMQs)?",o:["A TV quiz show about British politics and MPs","A weekly Commons session where MPs question the PM","A monthly press conference the PM holds for reporters","An annual televised debate between all party leaders"],a:1,exp:"PMQs takes place every Wednesday when Parliament is sitting. MPs — particularly the Leader of the Opposition — question the Prime Minister. It is a key form of parliamentary accountability."},

// ── VALUES & SOCIETY (harder) ─────────────────────────────
{cat:"Values & Society",q:"What does 'tolerance' mean as a British value?",o:["Agreeing with everyone else's personal views","Accepting others may hold different opinions and faiths","Overlooking illegal acts if they are culturally driven","Enforcing a single set of beliefs on all citizens"],a:1,exp:"Tolerance means accepting that others have the right to hold different views, practise different religions and live differently — as long as they stay within the law and respect others' rights."},
{cat:"Values & Society",q:"What are the three branches of the UK state?",o:["The Crown, Parliament and the Military","The Legislature, the Executive and the Judiciary","The Lords, the Commons and the Monarch","The Home Office, Foreign Office and Treasury"],a:1,exp:"The three branches are: the Legislature (Parliament — makes laws), the Executive (government — implements laws) and the Judiciary (courts — interprets laws). Their separation prevents any one branch having too much power."},
{cat:"Values & Society",q:"What is the significance of the Bill of Rights 1689?",o:["It gave all adult men the legal right to vote","It established Parliament's supremacy over the Crown","It formally created the position of Prime Minister","It united the Kingdoms of England and Scotland"],a:1,exp:"The Bill of Rights 1689, following the Glorious Revolution, confirmed Parliament's supremacy over the Crown, established free elections, freedom of speech in Parliament, and prohibited cruel punishments."},
{cat:"Values & Society",q:"What does 'equality before the law' mean?",o:["Everyone receives the same sentence for the same crime","The law applies equally to all people regardless of wealth, status or background","Only citizens have full legal rights","Judges must always side with the less wealthy party"],a:1,exp:"Equality before the law means the same laws apply to everyone — rich or poor, powerful or ordinary. No one, including the government, is above the law."},

// ── A MODERN SOCIETY (harder) ─────────────────────────────
{cat:"A Modern Society",q:"What is the Notting Hill Carnival?",o:["A traditional English harvest festival in west London","Europe's largest street festival, celebrating Caribbean culture","An annual film awards ceremony held in London","A celebration of the Norman conquest"],a:1,exp:"The Notting Hill Carnival, held annually in London on the August bank holiday, is Europe's largest street festival. It celebrates Caribbean — particularly Trinidadian — culture and heritage."},
{cat:"A Modern Society",q:"What famous sporting event is held at Epsom Downs each June?",o:["The Grand National","The Cheltenham Gold Cup","The Derby","The Royal Ascot"],a:2,exp:"The Derby is one of Britain's most famous flat horse races, held at Epsom Downs in Surrey each June. It is part of the Classic series of races and attracts huge crowds."},
{cat:"A Modern Society",q:"Which Scottish city is famous for its annual International Festival and Fringe?",o:["Glasgow","Aberdeen","Inverness","Edinburgh"],a:3,exp:"Edinburgh hosts the world-famous Edinburgh International Festival and the Edinburgh Fringe — the world's largest arts festival — every August, attracting performers and visitors from around the globe."},
{cat:"A Modern Society",q:"What is the name of the annual flower show held in Chelsea, London?",o:["The Hampton Court Show","The Royal Horticultural Show","The Chelsea Flower Show","The Kew Gardens Festival"],a:2,exp:"The Chelsea Flower Show, organised by the Royal Horticultural Society (RHS), is held annually in the grounds of the Royal Hospital Chelsea. It is the world's most famous flower show."},
{cat:"A Modern Society",q:"Which famous structure, completed in 1894, spans the River Thames in London?",o:["Waterloo Bridge","Westminster Bridge","London Bridge","Tower Bridge"],a:3,exp:"Tower Bridge, completed in 1894, is one of London's most iconic landmarks. Its distinctive Victorian Gothic towers and bascule design make it instantly recognisable worldwide."},
{cat:"A Modern Society",q:"Who wrote 'A Brief History of Time', a landmark popular science book?",o:["Richard Dawkins","Tim Berners-Lee","Stephen Hawking","James Watson"],a:2,exp:"Stephen Hawking (1942--2018), the Cambridge physicist, wrote 'A Brief History of Time' (1988), which brought complex cosmology to a mass audience. Despite severe disability, he made groundbreaking contributions to physics."},
{cat:"A Modern Society",q:"Who invented the World Wide Web in 1989?",o:["Alan Turing","Tim Berners-Lee","Clive Sinclair","James Dyson"],a:1,exp:"Sir Tim Berners-Lee, a British scientist working at CERN, invented the World Wide Web in 1989. He proposed a system of information sharing using hypertext that became the foundation of the modern internet."},
{cat:"A Modern Society",q:"What did Alan Turing contribute to British history?",o:["He invented the first working telephone","He pioneered computing and helped crack the Enigma code","He discovered the structure of DNA with others","He designed the Spitfire fighter aircraft in WW2"],a:1,exp:"Alan Turing (1912--1954) was a pioneering mathematician and computer scientist. His work breaking the German Enigma cipher at Bletchley Park during WW2 is credited with significantly shortening the war."},

// ── NATIONS & SYMBOLS (harder) ───────────────────────────
{cat:"Nations & Symbols",q:"What is the name of the Scottish national epic poem, written by Robert Burns?",o:["The Lady of the Lake","Tam o' Shanter","Auld Lang Syne","The Bruce"],a:1,exp:"'Tam o' Shanter' (1790) is Robert Burns's best-known narrative poem. Burns (1759--1796) is Scotland's national poet, celebrated on Burns Night (25 January) each year."},
{cat:"Nations & Symbols",q:"What is 'Burns Night'?",o:["A Scottish festival held on 25 January celebrating poet Robert Burns","A bonfire night tradition unique to Scotland","A memorial for those who died in the Battle of Culloden","A harvest festival in the Scottish Highlands"],a:0,exp:"Burns Night (25 January) celebrates the life and poetry of Robert Burns. Festivities include a Burns Supper with haggis, neeps and tatties, recitation of Burns's poems, and toasts."},
{cat:"Nations & Symbols",q:"What is the highest mountain in the UK?",o:["Scafell Pike","Snowdon","Ben Nevis","Slieve Donard"],a:2,exp:"Ben Nevis in Scotland (1,345m) is the highest mountain in the UK. Scafell Pike is the highest in England, Snowdon in Wales, and Slieve Donard in Northern Ireland."},
{cat:"Nations & Symbols",q:"What is the longest river in the UK?",o:["The Thames","The Severn","The Trent","The Clyde"],a:1,exp:"The River Severn (354km) is the longest river in the UK, flowing through Wales and England into the Bristol Channel. The Thames (346km) is the longest river entirely within England."},
{cat:"Nations & Symbols",q:"What is the capital city of Wales?",o:["Swansea","Newport","Caernarfon","Cardiff"],a:3,exp:"Cardiff (Caerdydd in Welsh) is the capital city of Wales and its largest city. It became the official capital in 1955."},
{cat:"Nations & Symbols",q:"What is the capital city of Scotland?",o:["Glasgow","Dundee","Edinburgh","Stirling"],a:2,exp:"Edinburgh is the capital of Scotland, home to the Scottish Parliament and Edinburgh Castle. Glasgow is Scotland's largest city but not its capital."},

// ── EVERYDAY LIFE (harder) ────────────────────────────────
{cat:"Everyday Life",q:"What is the non-emergency police number in the UK?",o:["999","112","101","111"],a:2,exp:"101 is the non-emergency police number for reporting crime or incidents that don't require an immediate response. 999 is for emergencies only."},
{cat:"Everyday Life",q:"At what age can you drive a car in the UK?",o:["16","17","18","21"],a:1,exp:"You can drive a car on public roads from age 17 in the UK, provided you have a provisional licence. You can apply for a provisional licence from age 15 years and 9 months."},
{cat:"Everyday Life",q:"What does it mean to 'stand' in a UK election?",o:["To campaign for another candidate","To put yourself forward as a candidate","To vote in person rather than by post","To serve as a polling station officer"],a:1,exp:"'Standing' in an election means putting yourself forward as a candidate. Candidates 'stand' for election; voters 'vote' for them. Any UK citizen aged 18+ can stand for most elected offices."},
{cat:"Everyday Life",q:"Which body regulates financial services in the UK?",o:["The Bank of England","The Financial Conduct Authority (FCA)","The Treasury","The Competition and Markets Authority"],a:1,exp:"The Financial Conduct Authority (FCA) regulates financial services firms and markets in the UK, protecting consumers and ensuring honest, fair markets. The Bank of England has separate regulatory responsibilities."},

// ── BRITISH HISTORY (early & medieval) ───────────────────────
{cat:"British History",q:"When did the Romans first invade Britain?",o:["55 BC, under Julius Caesar","43 AD, under Emperor Claudius","122 AD, when Hadrian's Wall was built","410 AD, when they left"],a:0,exp:"Julius Caesar made the first Roman expedition to Britain in 55 BC (and again in 54 BC), but did not conquer it. The full Roman conquest began in 43 AD under Emperor Claudius."},
{cat:"British History",q:"Who was Boudicca?",o:["A Roman empress who once governed Britain","A Celtic Iceni queen who led a revolt against Rome","A Saxon princess who unified the English kingdoms","A Viking queen who settled in northern England"],a:1,exp:"Boudicca was queen of the Iceni tribe in eastern Britain. She led a revolt against Roman occupation around 60–61 AD, destroying Colchester, London and St Albans before being defeated."},
{cat:"British History",q:"Who were the Anglo-Saxons?",o:["Roman soldiers who stayed on after the legions left","Germanic tribes who settled in England after the Romans","Viking raiders from Scandinavia who invaded later","Celtic tribes who migrated from Gaul to Britain"],a:1,exp:"The Anglo-Saxons were Germanic tribes — Angles, Saxons and Jutes — who settled in England after the Romans left. They gave England its name ('Angle-land') and established the kingdoms that preceded Norman England."},
{cat:"British History",q:"Who was King Alfred the Great?",o:["A Norman king who conquered England in 1066","A Viking king who briefly ruled all of England","A Saxon king of Wessex who fought the Vikings","The first Tudor monarch of England and Wales"],a:2,exp:"Alfred the Great (849–899) was King of Wessex who successfully resisted the Viking invasions. He promoted education and literacy and is the only English monarch called 'the Great'."},
{cat:"British History",q:"What was the feudal system introduced by the Normans?",o:["A system of elected local village government","A hierarchy of king, nobles and peasants tied to land","A trading system running between English towns","A church-based system of ecclesiastical courts"],a:1,exp:"The feudal system placed the king at the top, nobles (barons and knights) below him, and peasants at the bottom. Land was held in exchange for loyalty and military service."},

// ── BRITISH HISTORY (Tudor to Victorian) ─────────────────────
{cat:"British History",q:"What was the significance of the Spanish Armada in 1588?",o:["Spain successfully invaded and occupied England","A Spanish invasion fleet was defeated by the English navy","Spain blockaded English ports for a full two years","The Spanish captured the English fleet off Plymouth"],a:1,exp:"Philip II of Spain sent an Armada of 130 ships to invade England in 1588. It was defeated by the English fleet (vice-admiral: Sir Francis Drake) and storms. The victory boosted English national confidence."},
{cat:"British History",q:"Who was Elizabeth I?",o:["A Stuart queen who returned England to Catholicism","A Tudor queen (1558–1603) who defeated the Spanish Armada","A Norman queen who oversaw the Domesday Book survey","The first queen ever to rule England on her own"],a:1,exp:"Elizabeth I (1558–1603) was one of England's greatest monarchs. Her long reign saw the defeat of the Spanish Armada, the flourishing of arts (Shakespeare, Marlowe) and significant overseas exploration."},
{cat:"British History",q:"What was the Gunpowder Plot of 1605?",o:["A Puritan plot to assassinate Queen Elizabeth I","A failed Catholic plot to blow up Parliament and James I","A Protestant plot to overthrow Queen Mary I","A Scottish plot against King James VI of Scotland"],a:1,exp:"The Gunpowder Plot was a failed conspiracy led by Robert Catesby (with Guy Fawkes guarding the gunpowder) to blow up Parliament and kill James I on 5 November 1605. It is commemorated every year with bonfires and fireworks."},
{cat:"British History",q:"What was the Restoration of 1660?",o:["The re-establishment of the Catholic Church in England","Charles II returned from exile and the monarchy was restored","Scotland was restored to full independence from England","Parliament was restored to full power after the Civil War"],a:1,exp:"After Oliver Cromwell's death, Parliament invited Charles II back from exile. The monarchy was restored in 1660, ending the republican Commonwealth that had ruled since 1649."},
{cat:"British History",q:"What was the significance of the Battle of Waterloo (1815)?",o:["Britain defeated the French navy off the coast of Spain","Napoleon was finally defeated by Wellington and the Prussians","Britain won the long Seven Years War against France","The French Revolution came to a formal end"],a:1,exp:"At Waterloo (18 June 1815), the Duke of Wellington and Prussian forces under Blücher defeated Napoleon. It ended the Napoleonic Wars and cemented Britain as the leading world power of the 19th century."},
{cat:"British History",q:"When did Britain abolish the transatlantic slave trade?",o:["1772","1807","1833","1865"],a:1,exp:"The Slave Trade Act 1807 abolished the trade in enslaved people across the British Empire. The Slavery Abolition Act 1833 then freed enslaved people throughout most of the Empire. William Wilberforce was a leading abolitionist."},
{cat:"British History",q:"What was the Great Exhibition of 1851?",o:["A trade fair displaying only British-made goods","An international exhibition in Hyde Park led by Prince Albert","A grand celebration of Queen Victoria's coronation","A military parade commemorating British victories"],a:1,exp:"The Great Exhibition (1851) was the world's first international exhibition, held in the Crystal Palace in Hyde Park, London. Organised largely by Prince Albert, it showcased Britain's industrial and imperial power to the world."},
{cat:"British History",q:"Who was Florence Nightingale?",o:["A best-selling Victorian novelist of her day","A pioneer of nursing during the Crimean War","The first woman elected as an MP to Parliament","A leading suffragette for women's right to vote"],a:1,exp:"Florence Nightingale (1820–1910) became famous during the Crimean War (1853–56) for transforming hospital care through rigorous hygiene. She is considered the founder of modern nursing and used statistics to argue for reform."},
{cat:"British History",q:"Who was Isambard Kingdom Brunel?",o:["A long-serving Victorian-era Prime Minister","An engineer of the Great Western Railway and Clifton Bridge","A scientist who developed the theory of evolution","A Scottish inventor of the first working steam engine"],a:1,exp:"Isambard Kingdom Brunel (1806–1859) was one of the greatest engineers of the Industrial Revolution, responsible for the Great Western Railway, the Clifton Suspension Bridge and the SS Great Britain steamship."},
{cat:"British History",q:"What were the Corn Laws and why were they repealed?",o:["Laws forcing farmers to grow corn — repealed after famine","Tariffs on imported grain keeping bread dear — repealed in 1846","Laws banning wool exports — repealed to boost overseas trade","Laws regulating brewing — repealed after large public protests"],a:1,exp:"The Corn Laws kept bread prices artificially high by taxing grain imports, benefiting landowners at the expense of the urban poor. PM Robert Peel repealed them in 1846 — a landmark victory for free trade and the growing industrial working class."},
{cat:"British History",q:"Who was Charles Dickens?",o:["A Victorian politician who reformed child labour laws","A novelist (Oliver Twist, A Christmas Carol) who exposed poverty","A Scottish poet who wrote about the industrial age","A scientist who pioneered the theory of evolution"],a:1,exp:"Charles Dickens (1812–1870) is one of the greatest English novelists. His works, including Oliver Twist, David Copperfield, Bleak House and A Christmas Carol, exposed poverty and injustice in Victorian society."},
{cat:"British History",q:"What was the significance of Indian independence in 1947?",o:["India chose to remain part of the British Empire","India and Pakistan gained independence on 15 August 1947","India became a republic straight away in 1947","Only Pakistan gained independence from Britain in 1947"],a:1,exp:"India gained independence on 15 August 1947, partitioned into India and Pakistan. It was one of the most significant events in the end of the British Empire and the modern history of South Asia."},
{cat:"British History",q:"What was the significance of the 1945 general election?",o:["Winston Churchill's Conservatives won a landslide","Labour under Attlee won and founded the welfare state and NHS","The Liberal Party won a general election for the first time","The first election in which any women in the UK could vote"],a:1,exp:"The 1945 general election saw a landslide for Labour under Clement Attlee, defeating Churchill despite his wartime popularity. The new government created the welfare state, founded the NHS (1948), and nationalised key industries."},
{cat:"British History",q:"Which famous Victorian engineer built the Clifton Suspension Bridge?",o:["George Stephenson","James Watt","Isambard Kingdom Brunel","Thomas Telford"],a:2,exp:"Isambard Kingdom Brunel designed the Clifton Suspension Bridge across the Avon Gorge in Bristol. Construction began in 1831 and was completed posthumously in 1864, five years after Brunel's death."},
{cat:"British History",q:"What was the 'Blitz' during World War II?",o:["The Allied amphibious invasion of Normandy in 1944","The German bombing of British cities in 1940–41","The Battle of Britain daylight air campaign","The German naval blockade of all British ports"],a:1,exp:"The Blitz was a German bombing campaign against Britain from September 1940 to May 1941, targeting London and other major cities. Tens of thousands of civilians were killed, but British morale held."},
{cat:"British History",q:"What did the Beveridge Report (1942) recommend?",o:["A detailed plan for post-war military alliances","A welfare state tackling Want, Disease, Ignorance, Squalor, Idleness","The full nationalisation of all British industry","A new written constitution for post-war Britain"],a:1,exp:"The Beveridge Report (1942), written by William Beveridge, proposed tackling five 'giant evils': Want, Disease, Ignorance, Squalor and Idleness. It laid the foundations for the post-war welfare state, including the NHS and National Insurance."},
{cat:"British History",q:"What was the Battle of Britain (1940)?",o:["Britain's invasion of France to liberate occupied Paris","The RAF's defence of Britain against the Luftwaffe","Britain's defeat of the German navy in the North Sea","The Allied capture of Berlin by British and US forces"],a:1,exp:"The Battle of Britain (summer 1940) saw the RAF successfully defend British skies against sustained Luftwaffe attacks. Churchill called it the RAF's 'finest hour'. The German failure to gain air superiority prevented the planned invasion of Britain."},

// ── GOVERNMENT & LAW (new) ────────────────────────────────────
{cat:"Government & Law",q:"What is the minimum voting age in UK general elections?",o:["16","17","18","21"],a:2,exp:"You must be 18 to vote in UK general elections. Scotland and Wales have lowered the voting age to 16 for their devolved elections, but UK-wide general elections require voters to be 18."},
{cat:"Government & Law",q:"How many MPs sit in the House of Commons?",o:["450","550","650","750"],a:2,exp:"There are 650 Members of Parliament (MPs) in the House of Commons, each representing one constituency. General elections are held to elect all 650 seats simultaneously."},
{cat:"Government & Law",q:"What is 'Royal Assent'?",o:["The monarch's permission to call a general election","The monarch's formal approval turning a bill into an Act","The monarch's appointment of a new Prime Minister","The right to display the Royal Coat of Arms"],a:1,exp:"Royal Assent is when the monarch formally approves a bill passed by both Houses of Parliament, making it law. In practice, Royal Assent is always granted — the last time it was refused was in 1708."},
{cat:"Government & Law",q:"What is a party manifesto?",o:["A confidential internal government document","A pre-election document setting out a party's promises","A formal written complaint submitted to Parliament","A draft bill before it becomes an Act of Parliament"],a:1,exp:"A manifesto is a public document published by a political party before an election, setting out its policies and promises. Voters can use manifestos to compare parties. A winning party is expected to implement its manifesto."},
{cat:"Government & Law",q:"What is the role of the Cabinet?",o:["Senior civil servants running the country day-to-day","Senior ministers who meet to agree policy, chaired by the PM","The cross-party committee of MPs that scrutinises government","The group of personal advisers in 10 Downing Street"],a:1,exp:"The Cabinet is the main decision-making body of government, comprising around 20–25 senior ministers. It meets weekly to decide policy. All Cabinet ministers are expected to support decisions publicly — 'collective responsibility'."},
{cat:"Government & Law",q:"What is the role of Select Committees in Parliament?",o:["They draft and write entirely new bills of law","Groups of MPs and Lords that scrutinise departments","They choose and elect a new Prime Minister","They decide sentences in serious criminal cases"],a:1,exp:"Select Committees are groups of MPs that examine specific government departments (e.g. Health, Treasury). They call ministers and civil servants to give evidence, investigate policy, and publish reports. They are a key accountability mechanism."},
{cat:"Government & Law",q:"What is the Chancellor of the Exchequer responsible for?",o:["Foreign affairs, embassies and diplomacy","The economy and public finances, including the Budget","Overseeing the courts and the legal system","Commanding the UK's armed forces in wartime"],a:1,exp:"The Chancellor of the Exchequer heads the Treasury and is responsible for economic and fiscal policy. Each year, the Chancellor presents the Budget — the government's plans for taxation and public spending."},
{cat:"Government & Law",q:"What is the Home Secretary responsible for?",o:["UK foreign policy and overseas diplomacy","Immigration, policing, security and prisons","UK economic policy and public finances","Schools, universities and national education"],a:1,exp:"The Home Secretary heads the Home Office, responsible for immigration and border control, national security, police funding, and the prison and probation service. It is one of the four great offices of state."},
{cat:"Government & Law",q:"What is a magistrates' court?",o:["The highest criminal appeal court in England","A court that handles most less serious criminal cases","A specialist court only for young offenders under 18","A civil court that hears contract and debt disputes"],a:1,exp:"Magistrates' courts deal with summary (less serious) offences and preliminary hearings for more serious cases. About 95% of criminal cases in England and Wales are handled entirely by magistrates, who are usually unpaid volunteers."},
{cat:"Government & Law",q:"What is judicial independence?",o:["Judges can create new laws without Parliament","Judges decide cases only on the law, free from politics","Judges are independent of any public scrutiny at all","Only judges may propose major constitutional changes"],a:1,exp:"Judicial independence means courts are free from political interference by the government. It is a cornerstone of the rule of law, ensuring citizens can challenge even the government in court and receive impartial justice."},
{cat:"Government & Law",q:"What is the purpose of the Crown Prosecution Service (CPS)?",o:["It manages the Royal Family's official finances","It decides whether to prosecute crimes in England and Wales","It runs the Crown Court and appoints judges","It provides legal aid to low-income defendants"],a:1,exp:"The CPS prosecutes criminal cases in England and Wales. It reviews evidence gathered by the police and decides whether there is enough to charge someone and whether prosecution is in the public interest. It is independent of the police."},
{cat:"Government & Law",q:"What does it mean to 'register to vote' in the UK?",o:["Joining and paying dues to a political party","Adding your name to the Electoral Register","Applying for a postal or proxy vote by post","Paying a one-off fee to vote in democracy"],a:1,exp:"To vote you must be on the Electoral Register. You register with your local council (online or by post). If you're not registered, you cannot vote. Registration is open to UK citizens, qualifying Commonwealth citizens and EU citizens (for some elections)."},
{cat:"Government & Law",q:"What is the role of the Foreign Secretary?",o:["Managing the UK's economy and finances","Leading UK foreign policy and overseas relations","Overseeing UK immigration and border policy","Managing the National Health Service daily"],a:1,exp:"The Foreign Secretary (Secretary of State for Foreign, Commonwealth and Development Affairs) is responsible for the UK's foreign policy, diplomatic relations, and overseas development. It is one of the four great offices of state."},
{cat:"Government & Law",q:"What is meant by 'collective Cabinet responsibility'?",o:["All Cabinet ministers are collectively responsible for their department's spending","All Cabinet ministers must publicly support government decisions, even if they disagreed in Cabinet","Cabinet ministers share a collective salary","All ministers are equally responsible for the PM's decisions"],a:1,exp:"Collective Cabinet responsibility means all ministers must publicly support Cabinet decisions, regardless of private disagreements. A minister who cannot support a decision is expected to resign. This maintains a united government front."},
{cat:"Government & Law",q:"What is the purpose of a 'Green Paper' in the UK?",o:["A government document on environmental policy","A consultation document inviting debate on proposals","A final piece of legislation ready to become law","A formal document issued by the House of Lords"],a:1,exp:"A Green Paper is a consultative document where the government sets out proposals for debate. It is followed by a White Paper (firmer proposals) and then, if appropriate, legislation. Green Papers invite public and parliamentary comment."},
{cat:"Government & Law",q:"What is the Northern Ireland Assembly?",o:["A UK Parliament committee covering Northern Ireland","The devolved legislature set up under the Good Friday Agreement","The local council for the city of Belfast only","A cross-border body with the Republic of Ireland"],a:1,exp:"The Northern Ireland Assembly is the devolved legislature established by the Good Friday Agreement (1998). It has powers over devolved matters such as health, education and agriculture. It uses a power-sharing system requiring unionist and nationalist participation."},

// ── VALUES & SOCIETY (new) ────────────────────────────────────
{cat:"Values & Society",q:"What is the minimum age to vote in UK general elections?",o:["16","17","18","21"],a:2,exp:"The voting age for UK general elections is 18. Scotland and Wales allow 16-year-olds to vote in their devolved elections. There is ongoing debate about whether to lower the UK-wide voting age to 16."},
{cat:"Values & Society",q:"What is the Equality Act 2010?",o:["A law requiring equal pay for men and women only","A law protecting against discrimination on protected grounds","A law requiring equal representation of men/women in Parliament","A law requiring equal access to all public services"],a:1,exp:"The Equality Act 2010 protects people from discrimination on nine protected characteristics: age, disability, gender reassignment, marriage/civil partnership, pregnancy, race, religion or belief, sex, and sexual orientation."},
{cat:"Values & Society",q:"What does 'freedom of religion' mean as a British value?",o:["Everyone must follow the Church of England by law","People may follow any religion or none, within the law","Only officially registered religions are permitted","Religious freedom only applies to UK-born citizens"],a:1,exp:"Freedom of religion or belief is a fundamental right in the UK. People are free to practise any religion or no religion, change their faith, and express their beliefs — within the limits of the law."},
{cat:"Values & Society",q:"What is parliamentary sovereignty?",o:["The Parliament building is given special protection","Parliament is the supreme law-maker; no court can override it","The monarch controls all decisions made in Parliament","Parliament is independent of any public accountability"],a:1,exp:"Parliamentary sovereignty means Parliament is the supreme legal authority in the UK. It can make or unmake any law. No Parliament can bind its successors, and courts interpret but cannot override Acts of Parliament."},
{cat:"Values & Society",q:"What is a 'pressure group' in British politics?",o:["A group of MPs who always vote the same way","An organisation campaigning to influence government policy","A group of voters organised in a marginal constituency","A secret advisory body sitting inside government"],a:1,exp:"Pressure groups (or interest groups) campaign on specific issues — for example environmental organisations, trade unions or business groups. They lobby government, Parliament and the public to influence policy without standing for election themselves."},
{cat:"Values & Society",q:"What does 'the rule of law' guarantee for individuals?",o:["That the government always wins cases in court","That everyone, including government, is under the law","That only UK citizens may enjoy legal rights","That laws can only be changed by public referendum"],a:1,exp:"The rule of law guarantees that laws apply equally to everyone — no one, including government ministers, is above the law. If the government acts unlawfully, citizens can challenge it in independent courts through 'judicial review'."},
{cat:"Values & Society",q:"What is the role of voluntary work in British society?",o:["Volunteering replaces most government services","Millions give time to charities, strengthening communities","Voluntary work is mainly done by retired people","It is required by law for all unemployed people"],a:1,exp:"Voluntary work is a cornerstone of British civic life. Millions of people volunteer in charities, community groups, sports clubs, hospitals and many other settings. The voluntary sector is distinct from the government and private sectors."},
{cat:"Values & Society",q:"What are the two Houses of Parliament?",o:["The Senate and the Assembly","The House of Commons and the House of Lords","The Upper House and the Lower Chamber","The Crown and Parliament"],a:1,exp:"Parliament consists of the House of Commons (elected MPs) and the House of Lords (appointed peers and bishops). Bills must pass both Houses before receiving Royal Assent. The Commons has ultimate authority."},
{cat:"Values & Society",q:"Who is the head of the Church of England?",o:["The Pope","The Archbishop of Canterbury","The monarch","The Prime Minister"],a:2,exp:"The monarch is the Supreme Governor of the Church of England. The Archbishop of Canterbury is its spiritual leader. This role dates from Henry VIII's break with Rome in the 1530s."},

// ── A MODERN SOCIETY (new) ────────────────────────────────────
{cat:"A Modern Society",q:"What are the four countries of the United Kingdom?",o:["England, Scotland, Wales and the Republic of Ireland","England, Scotland, Wales and Northern Ireland","England, Scotland, Wales and the Isle of Man","England, Scotland, Wales and the Channel Islands"],a:1,exp:"The United Kingdom consists of England, Scotland, Wales and Northern Ireland. The Republic of Ireland is a separate, independent country. The Isle of Man and Channel Islands are Crown Dependencies, not part of the UK."},
{cat:"A Modern Society",q:"Approximately what is the population of the United Kingdom?",o:["Around 47 million","Around 57 million","Around 67 million","Around 80 million"],a:2,exp:"The UK population is approximately 67 million. England is by far the most populous country (around 56 million), followed by Scotland (about 5.5 million), Wales (about 3.2 million) and Northern Ireland (about 1.9 million)."},
{cat:"A Modern Society",q:"What is the 'Windrush generation'?",o:["Engineers who built Britain's post-war motorway network","Caribbean migrants invited to the UK from 1948 for labour","Welsh miners who moved to London after the pits closed","German POWs who stayed on in Britain after 1945"],a:1,exp:"The Windrush generation refers to the hundreds of thousands of people who came from Caribbean Commonwealth countries from 1948. The Empire Windrush was the first ship to bring large numbers. They contributed enormously to the NHS, transport and many other sectors."},
{cat:"A Modern Society",q:"What is the Grand National?",o:["A cross-country running race held in the Lake District","An annual horse race held at Aintree near Liverpool","A gruelling cycling race held across the Scottish Highlands","The UK's biggest annual motor racing championship"],a:1,exp:"The Grand National is one of the most famous horse races in the world, held annually at Aintree Racecourse near Liverpool. It features a large field of horses over a challenging course with distinctive fences and is watched by millions."},
{cat:"A Modern Society",q:"What sport is the Wimbledon Championship associated with?",o:["Cricket","Rugby","Tennis","Athletics"],a:2,exp:"Wimbledon (the All England Lawn Tennis Championships) is the world's oldest and most prestigious tennis Grand Slam, held annually in London. It is famous for its grass courts, strict dress code and tradition of strawberries and cream."},
{cat:"A Modern Society",q:"What is 'Hogmanay'?",o:["A traditional Scottish meat and oat dish","The Scottish New Year celebration on 31 December","A Welsh harvest festival held each autumn","A Northern Irish traditional music festival"],a:1,exp:"Hogmanay is the Scottish New Year celebration. Edinburgh's Hogmanay is one of the world's largest New Year parties. Traditions include first-footing (being the first to enter a neighbour's home after midnight) and singing Auld Lang Syne."},
{cat:"A Modern Society",q:"Which British author wrote the Harry Potter series?",o:["Agatha Christie","Roald Dahl","J.K. Rowling","Ian Fleming"],a:2,exp:"J.K. Rowling wrote the seven Harry Potter novels, beginning with Harry Potter and the Philosopher's Stone (1997). The series has sold over 500 million copies worldwide and is one of the best-selling book series in history."},
{cat:"A Modern Society",q:"Who discovered the structure of DNA?",o:["Isaac Newton with his colleague Robert Hooke","Francis Crick and James Watson, aided by Rosalind Franklin","Charles Darwin along with Thomas Huxley","Stephen Hawking alongside Roger Penrose"],a:1,exp:"The double helix structure of DNA was discovered in 1953 by Francis Crick and James Watson, building on X-ray crystallography work by Rosalind Franklin. Crick and Watson (with Maurice Wilkins) received the Nobel Prize in 1962."},
{cat:"A Modern Society",q:"What is the Tate Modern?",o:["A modern government office building in Westminster","A London modern art gallery in a former power station","A large hands-on science museum in Manchester","A popular theatre in London's West End district"],a:1,exp:"Tate Modern is one of the world's most visited art galleries, opened in 2000 in the converted Bankside Power Station on the South Bank in London. Admission to the main collection is free."},
{cat:"A Modern Society",q:"What is the Chelsea Flower Show?",o:["An annual garden party at Buckingham Palace","An annual show at the Royal Hospital Chelsea","A weekly flower market held in west London","A national competition for amateur gardeners"],a:1,exp:"The Chelsea Flower Show is held each May in the grounds of the Royal Hospital Chelsea by the Royal Horticultural Society (RHS). It is the world's most famous flower show, showcasing innovative garden designs and plants."},
{cat:"A Modern Society",q:"What does the National Trust do?",o:["A government body that manages the national debt","A charity protecting historic buildings and countryside","A government body that runs the national parks","A bank offering savings accounts to the public"],a:1,exp:"The National Trust is a conservation charity founded in 1895. It protects and opens to the public hundreds of historic houses, gardens, nature reserves and miles of coastline across England, Wales and Northern Ireland. It is one of the UK's largest charities."},
{cat:"A Modern Society",q:"What is the significance of the Edinburgh Festival each August?",o:["It is Scotland's main annual national sporting event","The world's largest arts festival — including the Fringe","A traditional Highland games event with piping and dancing","A celebration of the 1513 Battle of Flodden Field"],a:1,exp:"Each August, Edinburgh becomes the world's arts capital. The Edinburgh International Festival (founded 1947) and the Edinburgh Fringe (the world's largest arts festival) together attract thousands of shows and hundreds of thousands of visitors from around the globe."},
{cat:"A Modern Society",q:"What is the significance of the NHS to British society?",o:["It is a private insurance-based healthcare network","Founded in 1948, free healthcare for all UK residents","It only provides urgent emergency services","It is owned and run by local UK councils"],a:1,exp:"The NHS (National Health Service), founded in 1948, is one of the world's largest publicly funded health services. It provides comprehensive healthcare free at the point of use to all UK residents, funded by taxation. It is widely regarded as a defining British institution."},

// ── NATIONS & SYMBOLS (new) ──────────────────────────────────
{cat:"Nations & Symbols",q:"What are the four patron saints of the UK nations?",o:["St George, St Andrew, St David and St Peter","St George, St Andrew, St David and St Patrick","St George, St Michael, St David and St Columba","St Edmund, St Andrew, St David and St Patrick"],a:1,exp:"England's patron saint is St George (23 April), Scotland's is St Andrew (30 November), Wales's is St David (1 March), and Northern Ireland/Ireland's is St Patrick (17 March)."},
{cat:"Nations & Symbols",q:"What is the capital city of Northern Ireland?",o:["Londonderry/Derry","Armagh","Lisburn","Belfast"],a:3,exp:"Belfast is the capital and largest city of Northern Ireland. It is famous for its Victorian architecture, linen and shipbuilding heritage (the Titanic was built there) and the Titanic Belfast museum."},
{cat:"Nations & Symbols",q:"What does the red dragon on the Welsh flag symbolise?",o:["Roman occupation of Wales","An ancient Welsh symbol from mythology and history","It was added to honour Henry VIII","Wales's coal mining heritage"],a:1,exp:"The red dragon (Y Ddraig Goch) has been associated with Wales since the early medieval period. The current Welsh flag — a red dragon on a green and white background — became official in 1959 and is one of the world's oldest national flags."},
{cat:"Nations & Symbols",q:"What is the significance of 11 November in the UK?",o:["Bonfire Night, marking the Gunpowder Plot","Remembrance Day, marking the 1918 armistice","The monarch's official birthday parade day","St Andrew's Day, the Scottish national day"],a:1,exp:"Remembrance Day (11 November) marks the armistice that ended the First World War at 11am on 11 November 1918. A two-minute silence is held at 11am. Remembrance Sunday (nearest Sunday) sees a national service at the Cenotaph on Whitehall."},
{cat:"Nations & Symbols",q:"What is 'Bonfire Night' and when is it celebrated?",o:["A midsummer fire festival held in late June","5 November — marking the failure of the Gunpowder Plot","A rural harvest festival held every October","A Viking-origin fire ceremony held in January"],a:1,exp:"Bonfire Night (Guy Fawkes Night) on 5 November commemorates the failure of the Gunpowder Plot of 1605. It is celebrated with bonfires, fireworks and the burning of 'guy' effigies across the UK."},
{cat:"Nations & Symbols",q:"What is the national animal of Scotland?",o:["The golden eagle","The stag","The unicorn","The red deer"],a:2,exp:"The unicorn is Scotland's national animal. It appears on the Scottish coat of arms and on the royal coat of arms of the United Kingdom (alongside the English lion). The unicorn historically symbolised power and independence."},
{cat:"Nations & Symbols",q:"What is the Cenotaph and where is it?",o:["A war memorial in Edinburgh's Princes Street","The national war memorial on Whitehall in London","A monument on the waterfront in Cardiff Bay","A memorial on the White Cliffs of Dover coast"],a:1,exp:"The Cenotaph on Whitehall, London, is the UK's central war memorial. It was unveiled in 1920. On Remembrance Sunday, the monarch, government, military and public gather there to lay wreaths and honour those who died in conflict."},
{cat:"Nations & Symbols",q:"What is the highest mountain in England?",o:["Ben Nevis","Snowdon","Scafell Pike","Helvellyn"],a:2,exp:"Scafell Pike (978m) in the Lake District, Cumbria, is the highest mountain in England. Ben Nevis (Scotland) is the highest in the UK, Snowdon (Wales) and Slieve Donard (Northern Ireland) are the highest in their countries."},
{cat:"Nations & Symbols",q:"What language is spoken in parts of Scotland alongside English?",o:["Welsh","Cornish","Scottish Gaelic","Manx"],a:2,exp:"Scottish Gaelic is spoken by around 57,000 people, mainly in the Highlands and Islands. Scots (a Germanic language) is also spoken across Scotland. Both are officially recognised alongside English."},
{cat:"Nations & Symbols",q:"What is the significance of the Last Night of the Proms?",o:["The final episode of a popular TV drama series","The closing concert of the BBC Proms classical season","The closing ceremony of the Edinburgh Fringe festival","A traditional Scottish music and dance celebration"],a:1,exp:"The Last Night of the Proms is the final concert of the BBC Proms season at the Royal Albert Hall. It features patriotic British pieces including 'Land of Hope and Glory', 'Rule, Britannia!' and 'Jerusalem', with a joyful, flag-waving atmosphere."},

// ── EVERYDAY LIFE (new) ──────────────────────────────────────
{cat:"Everyday Life",q:"What number should you call for non-emergency NHS medical advice?",o:["999","101","111","112"],a:2,exp:"111 provides non-emergency NHS medical advice 24 hours a day. Call if you need urgent medical help but it's not life-threatening. 999 is for genuine emergencies only."},
{cat:"Everyday Life",q:"What is National Insurance (NI)?",o:["A government-run home insurance scheme for all","Contributions funding the NHS, state pension and benefits","A private insurance scheme offered only by banks","A special tax only levied on the self-employed"],a:1,exp:"National Insurance is a system of contributions paid by employees (from wages), employers and the self-employed. NI funds the NHS, state pension, and social security benefits. Your NI number (a unique reference) tracks your contributions."},
{cat:"Everyday Life",q:"What qualifications do students in England typically sit at age 16?",o:["A-levels taken at age 18 in sixth form","GCSEs — General Certificates of Secondary Education","National Vocational Qualifications only, no exams","The International Baccalaureate diploma programme"],a:1,exp:"Students in England usually take GCSEs at age 15–16, in a range of subjects. GCSEs are graded 9–1 (previously A*–G). They are the main qualification at the end of compulsory secondary education."},
{cat:"Everyday Life",q:"What are A-levels?",o:["School qualifications taken at age 16 (GCSEs)","Advanced level qualifications taken at 18, for university","A type of on-the-job paid apprenticeship scheme","Vocational qualifications for specific trade skills"],a:1,exp:"A-levels (Advanced Levels) are academic qualifications usually studied in sixth form or college between ages 16 and 18. They are the main route to university in England, Wales and Northern Ireland. Students typically take 3 A-levels."},
{cat:"Everyday Life",q:"What is a 'council house' or 'social housing'?",o:["Private housing built on council-owned land","Affordable rented housing from councils or associations","Short-term temporary housing provided for tourists","Housing provided entirely free to every UK citizen"],a:1,exp:"Council housing (social housing) is affordable rented accommodation owned by local councils or housing associations. The Right to Buy scheme (introduced 1980) allowed many tenants to purchase their homes at a discount."},
{cat:"Everyday Life",q:"What is Citizens Advice?",o:["A government-run immigration advice service","A charity network giving free legal, housing, money advice","A private legal firm offering reduced fees to clients","A government department handling welfare claim cases"],a:1,exp:"Citizens Advice is a network of independent charities providing free, impartial advice on topics including benefits, debt, housing, employment and consumer rights. There are hundreds of local Citizens Advice offices across the UK."},
{cat:"Everyday Life",q:"What does it mean to register with a GP?",o:["Paying a one-off fee to access NHS services","Signing up with a local GP surgery as your doctor","Applying for cover from a private health insurer","Registering with the Department of Health by post"],a:1,exp:"To access NHS primary care, you register with a local GP (General Practitioner) surgery. Registration is free. You can then see your GP for health concerns, referrals and prescriptions. You should register when you move to a new area."},
{cat:"Everyday Life",q:"What is the minimum age to buy alcohol in the UK?",o:["16","17","18","21"],a:2,exp:"You must be 18 or over to buy alcohol in the UK. It is also illegal for anyone to buy alcohol for someone under 18 to consume in a licensed premises."},
{cat:"Everyday Life",q:"What is the legal age of marriage in England and Wales without parental consent?",o:["16","17","18","21"],a:2,exp:"You must be 18 to marry without parental consent in England and Wales. The Marriage and Civil Partnership (Minimum Age) Act 2022 raised the minimum age to 18 in all circumstances, removing the previous exception that allowed 16–17 year olds to marry with parental consent."},
{cat:"Everyday Life",q:"What is the driving test in the UK made up of?",o:["Only a practical on-road driving test","A theory test (with hazard perception) plus a practical","Only a written multiple-choice theory test","A medical exam together with a practical test"],a:1,exp:"To get a full driving licence in the UK, you must pass both a theory test (multiple-choice questions and hazard perception) and a practical driving test. You must hold a provisional licence and be at least 17."},

// ── UK & WORLD (new) ─────────────────────────────────────────
{cat:"UK & World",q:"What were the D-Day landings of 6 June 1944?",o:["The German invasion of Britain from the coast","The Allied amphibious invasion of Normandy in France","The liberation of Paris by British forces alone","Britain's first military action of the Second World War"],a:1,exp:"D-Day (Operation Overlord, 6 June 1944) was the Allied invasion of occupied France. Over 150,000 Allied troops landed on Normandy beaches. The success of the landings opened a western front and led to the liberation of Western Europe."},
{cat:"UK & World",q:"When did the UK join the European Economic Community (EEC)?",o:["1957","1963","1973","1979"],a:2,exp:"The UK joined the EEC (now the EU) on 1 January 1973 under Prime Minister Edward Heath. The UK had previously applied twice but was vetoed by France's President de Gaulle in 1963 and 1967."},
{cat:"UK & World",q:"What was the result of the 2016 Brexit referendum?",o:["The UK voted to remain in the EU by 52% to 48%","The UK voted to leave the EU by 52% to 48%","The result was too close to call and was held again","Only England voted to leave — Scotland and Wales voted to remain"],a:1,exp:"In the June 2016 referendum, 51.9% voted to leave the EU and 48.1% voted to remain. England and Wales voted Leave; Scotland and Northern Ireland voted Remain. The UK formally left the EU on 31 January 2020."},
{cat:"UK & World",q:"What is the Good Friday Agreement (1998)?",o:["A UK–Republic of Ireland fishing waters agreement","A peace deal largely ending the Troubles in Northern Ireland","An agreement to close all UK pubs on Good Friday","A trade deal between the UK and the Republic of Ireland"],a:1,exp:"The Good Friday Agreement (Belfast Agreement, 1998) brought an end to most of the violence of the Troubles in Northern Ireland. It established a power-sharing Assembly, cross-border bodies between Northern Ireland and the Republic, and normalised UK–Ireland relations."},
{cat:"UK & World",q:"What is Britain's 'special relationship'?",o:["The close relationship between England and Scotland","The uniquely close UK–US diplomatic and military ties","The UK's privileged trade links with the Commonwealth","The UK's unique dual membership of NATO and the UN"],a:1,exp:"The 'special relationship' describes the particularly close ties between the UK and the USA. The term was popularised by Winston Churchill. It encompasses military alliances (including NATO), intelligence sharing (Five Eyes), and close cultural and economic links."},
{cat:"UK & World",q:"How many permanent members does the UN Security Council have?",o:["3","5","7","10"],a:1,exp:"The UN Security Council has five permanent members: the United States, Russia, China, France and the United Kingdom. Each has a veto over Security Council resolutions. There are also 10 non-permanent elected members."},
{cat:"UK & World",q:"What is the Commonwealth of Nations?",o:["A military alliance of 56 nations led by the UK","A voluntary association of 56 mostly ex-British countries","A trading bloc that replaced UK EU membership","Countries which still officially use the pound sterling"],a:1,exp:"The Commonwealth is a voluntary association of 56 countries. It promotes democracy, development and international cooperation. Members include countries from Africa, Asia, the Caribbean and the Pacific. There are no formal political or economic obligations."},
{cat:"UK & World",q:"What role does the UK play in the United Nations?",o:["The UK is just a non-voting UN observer","A founding member and permanent UN Security Council member","The UK funds the UN but has no voting rights at all","The UK only joined the UN in the year 1990"],a:1,exp:"The UK is a founding member of the UN (1945) and one of five permanent members of the Security Council (alongside the US, Russia, China and France). Each permanent member holds veto power over Security Council resolutions."},
{cat:"UK & World",q:"What does the UK contribute to international development aid?",o:["The UK provides no official overseas development aid","One of the largest aid donors, with a 0.7% GNI target","The UK only provides military aid to its allies","Aid is given only to Commonwealth member countries"],a:1,exp:"The International Development (Official Development Assistance Target) Act 2015 required the UK to spend 0.7% of gross national income (GNI) on overseas development aid. The UK is consistently among the world's largest aid donors, supporting health, education and humanitarian relief."},
{cat:"UK & World",q:"What is NATO and when was it founded?",o:["A European trading organisation founded in 1957","The North Atlantic Treaty Organisation, founded in 1949","A United Nations peacekeeping operations body","A Commonwealth-wide defence and mutual aid pact"],a:1,exp:"NATO (North Atlantic Treaty Organisation) was founded in 1949. It is a military alliance of (currently 32) member states. Article 5 of the NATO treaty states that an attack on one member is considered an attack on all. The UK is a founding member."},

// ── EXPANSION BANK ───────────────────────────────────────────
// VALUES & SOCIETY (expansion)
{cat:"Values & Society",q:"At what age can a UK citizen vote in a general election?",o:["16","18","21","25"],a:1,exp:"The voting age for UK general elections is 18. Scottish Parliament and Senedd (Welsh Parliament) elections allow voting from age 16."},
{cat:"Values & Society",q:"What is meant by 'mutual respect and tolerance'?",o:["Agreeing with everyone's views regardless","Respecting others' rights to hold different beliefs","Following the majority opinion at all times","Avoiding contact with people of other faiths"],a:1,exp:"Mutual respect means accepting that others have the right to hold beliefs different from your own. It is one of the four fundamental British values."},
{cat:"Values & Society",q:"What is forced marriage?",o:["A marriage where both spouses are arranged by family","A marriage where one or both parties do not consent","Any marriage between people from different countries","A traditional cultural marriage celebration"],a:1,exp:"Forced marriage — where one or both spouses do not consent — is illegal in the UK. It differs from arranged marriage, in which both parties freely consent."},
{cat:"Values & Society",q:"Is domestic violence a criminal offence in the UK?",o:["Only if serious physical injury is caused","Yes — it is a criminal offence in all forms","Only if reported to police within 24 hours","Only if it occurs outside the family home"],a:1,exp:"Domestic violence — physical, emotional or financial abuse within the home — is a criminal offence. Police take all reports seriously and the law protects all family members."},
{cat:"Values & Society",q:"What does the Equality Act 2010 protect against?",o:["Only racial discrimination at work","Discrimination on grounds including age, sex, race, disability","Only discrimination by government bodies","Only discrimination in housing and education"],a:1,exp:"The Equality Act 2010 prohibits discrimination on protected grounds including age, disability, gender reassignment, race, religion, sex, sexual orientation, marriage and pregnancy."},
{cat:"Values & Society",q:"What is volunteering?",o:["Paid part-time work for charities","Working unpaid to help others or your community","Compulsory community service ordered by courts","A government training scheme for unemployed people"],a:1,exp:"Volunteering means giving your time unpaid to help others or your community. It is highly valued in UK society and helps build stronger communities."},
{cat:"Values & Society",q:"Who can stand as a candidate in UK elections?",o:["Only members of major political parties","Most UK, Irish or Commonwealth citizens aged 18+","Only those born in the UK","Only people with a university degree"],a:1,exp:"Most UK, Irish and Commonwealth citizens aged 18 or over can stand for election. Some occupations (judges, civil servants, police, armed forces) are restricted."},
{cat:"Values & Society",q:"What is the responsibility of UK citizens regarding the environment?",o:["No specific responsibilities are placed on citizens","To recycle, reduce waste and protect natural surroundings","Only businesses have environmental responsibilities","Only the government bears this responsibility"],a:1,exp:"Citizens are encouraged to look after the environment by recycling, reducing waste and respecting public spaces. Many local authorities run recycling schemes."},
{cat:"Values & Society",q:"Are men and women equal under UK law?",o:["Yes — they have equal rights in all areas of life","Only in employment, not in family law","Only since the year 2000","No — men have additional legal rights"],a:0,exp:"Men and women are equal under UK law. Equal pay, equal opportunity, and equal rights in family and public life are all protected by law."},
{cat:"Values & Society",q:"At what age must children in the UK attend school?",o:["From age 4 to age 14","From age 5 to age 16","From age 6 to age 18","Schooling is voluntary for all ages"],a:1,exp:"Education is compulsory for children aged 5--16 in England and Wales. Young people in England must remain in education or training until age 18."},
{cat:"Values & Society",q:"Is female genital mutilation (FGM) legal in the UK?",o:["Yes, if performed by a qualified doctor","No — it is a criminal offence","Yes, with parental consent for adults","Only legal under religious exemption"],a:1,exp:"FGM is illegal in the UK. It is also illegal to take a girl abroad to have FGM performed. The maximum penalty is 14 years' imprisonment."},
{cat:"Values & Society",q:"What is the responsibility of those who become British citizens?",o:["To attend Parliament once every 5 years","To respect UK laws, values and traditions and integrate","To declare loyalty only to their country of origin","To vote only for one specific political party"],a:1,exp:"New British citizens are expected to respect UK laws, values and traditions, integrate into society and contribute to community life. They take an oath at a citizenship ceremony."},

// BRITISH HISTORY (expansion)
{cat:"British History",q:"When did the Romans leave Britain?",o:["55 BC","43 AD","410 AD","1066"],a:2,exp:"The Romans withdrew from Britain around 410 AD, when troops were needed to defend Rome from invasions elsewhere. This ended nearly 400 years of Roman rule."},
{cat:"British History",q:"What is Stonehenge?",o:["A Roman fort in southern England","A prehistoric stone circle in Wiltshire","A medieval cathedral in Salisbury","A Saxon burial site in Kent"],a:1,exp:"Stonehenge in Wiltshire is a prehistoric stone monument built around 2500 BC during the Bronze Age. It is one of the world's most famous archaeological sites and a UNESCO World Heritage Site."},
{cat:"British History",q:"Who was Alfred the Great?",o:["A Norman king who built castles","A Saxon king of Wessex who fought the Vikings","A Roman emperor who visited Britain","A medieval king who signed Magna Carta"],a:1,exp:"Alfred the Great (849--899) was King of Wessex. He defended his kingdom against Viking invasions and is the only English monarch known as 'the Great'."},
{cat:"British History",q:"In which year did Vikings first raid the monastery at Lindisfarne?",o:["597","793","1066","1215"],a:1,exp:"In 793 AD, Viking raiders attacked the monastery at Lindisfarne in Northumbria. This is traditionally seen as the start of the Viking Age in Britain."},
{cat:"British History",q:"What were the Wars of the Roses?",o:["Wars between England and France in the 15th century","Civil wars between the houses of Lancaster and York","Religious wars between Catholics and Protestants","Border wars between England and Scotland"],a:1,exp:"The Wars of the Roses (1455--85) were civil wars for the English throne between the houses of Lancaster (red rose) and York (white rose). They ended at Bosworth in 1485."},
{cat:"British History",q:"Who was the last Tudor monarch?",o:["Henry VIII","Mary I","Elizabeth I","James I"],a:2,exp:"Elizabeth I (reigned 1558--1603) was the last Tudor monarch. She died unmarried and childless, succeeded by James I (James VI of Scotland), the first Stuart king of England."},
{cat:"British History",q:"What was the Bill of Rights 1689?",o:["A set of human rights protections for all citizens","A document confirming Parliament's power over the monarch","A constitution written for the American colonies","A treaty between England and the European powers"],a:1,exp:"The Bill of Rights 1689 confirmed Parliament's supremacy over the monarch following the Glorious Revolution. It limited royal power and required parliamentary consent for laws and taxes."},
{cat:"British History",q:"What did the 1801 Act of Union create?",o:["The Kingdom of Great Britain (England and Scotland)","The United Kingdom of Great Britain and Ireland","A union between England and Wales","A union between Britain and the colonies"],a:1,exp:"The Act of Union 1800 (effective 1801) joined Great Britain with Ireland to form the United Kingdom of Great Britain and Ireland."},
{cat:"British History",q:"When did the First World War begin and end?",o:["1914--1918","1916--1920","1939--1945","1900--1905"],a:0,exp:"The First World War lasted from 1914 to 1918. The UK entered after Germany invaded Belgium. The armistice was signed on 11 November 1918, marked annually as Remembrance Day."},
{cat:"British History",q:"When did the Second World War begin and end?",o:["1914--1918","1939--1945","1939--1944","1940--1946"],a:1,exp:"The Second World War (1939--1945) began when Britain declared war on Germany following the invasion of Poland. It ended in Europe in May 1945 (VE Day) and globally in August 1945 (VJ Day)."},

// A MODERN SOCIETY (expansion)
{cat:"A Modern Society",q:"Who is the Supreme Governor of the Church of England?",o:["The Archbishop of Canterbury","The Pope","The reigning monarch","The Prime Minister"],a:2,exp:"The reigning monarch is Supreme Governor of the Church of England. The Archbishop of Canterbury is the most senior cleric. The Church of England is the established church."},
{cat:"A Modern Society",q:"Which is NOT one of the main religions practised in the UK?",o:["Christianity","Islam","Hinduism","Shinto"],a:3,exp:"The main religions in the UK are Christianity, Islam, Hinduism, Sikhism, Judaism and Buddhism. Shinto, a Japanese religion, has very few adherents in the UK."},
{cat:"A Modern Society",q:"Approximately what is the UK's population?",o:["About 30 million","About 67 million","About 90 million","About 120 million"],a:1,exp:"The UK has a population of approximately 67 million (2021 census), making it one of the larger countries in Europe."},
{cat:"A Modern Society",q:"Which sport is associated with Wimbledon?",o:["Cricket","Tennis","Golf","Rugby"],a:1,exp:"The Wimbledon Championships, held in southwest London since 1877, is the oldest tennis tournament in the world and one of the four Grand Slam tournaments."},
{cat:"A Modern Society",q:"What is 'The Ashes'?",o:["A cricket series between England and Australia","An athletics meeting at Crystal Palace","A horse race held annually in Surrey","A boxing championship held in Manchester"],a:0,exp:"The Ashes is a Test cricket series played between England and Australia, dating back to 1882. It is one of the oldest and most famous rivalries in international sport."},
{cat:"A Modern Society",q:"Where is the Grand National horse race held?",o:["Ascot in Berkshire","Epsom Downs in Surrey","Aintree near Liverpool","Cheltenham in Gloucestershire"],a:2,exp:"The Grand National is held annually at Aintree Racecourse near Liverpool. It is one of the most famous steeplechase races in the world, attracting global attention."},
{cat:"A Modern Society",q:"Who invented the World Wide Web?",o:["Bill Gates","Tim Berners-Lee","Steve Jobs","Alan Turing"],a:1,exp:"Sir Tim Berners-Lee, a British computer scientist, invented the World Wide Web in 1989 while working at CERN. He proposed a system of linked hypertext documents."},
{cat:"A Modern Society",q:"What is the Booker Prize?",o:["A British prize for the year's best novel","An annual prize for British science writing","A prize awarded for charity fundraising","A music industry award for British artists"],a:0,exp:"The Booker Prize is awarded annually for the best novel written in English and published in the UK or Ireland. It is one of the world's most prestigious literary awards."},
{cat:"A Modern Society",q:"Who wrote the Harry Potter novels?",o:["Roald Dahl","JK Rowling","Philip Pullman","Enid Blyton"],a:1,exp:"JK Rowling wrote the Harry Potter series, published 1997--2007. The seven novels became a global phenomenon, spawning films, theme parks and stage productions."},
{cat:"A Modern Society",q:"Who was Sir Winston Churchill?",o:["A Victorian poet and writer","A 20th-century PM who led Britain in WWII","An economist who advised Margaret Thatcher","A Liberal PM at the start of WWI"],a:1,exp:"Winston Churchill (1874--1965) was Prime Minister 1940--45 and again 1951--55. He led Britain through the Second World War and is regarded as one of the greatest British leaders."},
{cat:"A Modern Society",q:"Who was the UK's first female Prime Minister?",o:["Theresa May","Margaret Thatcher","Liz Truss","Barbara Castle"],a:1,exp:"Margaret Thatcher (Conservative) was the UK's first female PM, serving 1979--1990. She was known as the 'Iron Lady' and led major economic reforms."},
{cat:"A Modern Society",q:"What is the name of the UK's national broadcaster?",o:["ITV","BBC","Channel 4","Sky News"],a:1,exp:"The British Broadcasting Corporation (BBC), founded in 1922, is the UK's national broadcaster. It is funded primarily by the TV licence fee and is editorially independent."},
{cat:"A Modern Society",q:"Who was Stephen Hawking?",o:["A British author of children's books","A leading 20th/21st century theoretical physicist","An MP and former Cabinet minister","A Nobel-winning British chemist"],a:1,exp:"Professor Stephen Hawking (1942--2018) was a renowned theoretical physicist who made groundbreaking contributions to the understanding of black holes and cosmology, despite living with motor neurone disease."},
{cat:"A Modern Society",q:"Which UK city is famous as the home of The Beatles?",o:["Manchester","Liverpool","Birmingham","Glasgow"],a:1,exp:"The Beatles formed in Liverpool in 1960. The city celebrates this heritage with sites including the Cavern Club and The Beatles Story museum at Albert Dock."},
{cat:"A Modern Society",q:"What is the most popular sport in the UK by participation and viewing?",o:["Cricket","Football (soccer)","Rugby","Tennis"],a:1,exp:"Football (soccer) is the most popular sport in the UK by both participation and viewing. The English Premier League is one of the most-watched football leagues in the world."},
{cat:"A Modern Society",q:"What are 'pubs' in the UK?",o:["Public houses serving alcohol and food","Government-owned community centres","Members-only social clubs","Wholesale food markets"],a:0,exp:"Pubs (public houses) are central to British social life, traditionally serving beer and food. Many date back centuries. The legal drinking age in licensed premises is 18."},
{cat:"A Modern Society",q:"Who composed 'Pomp and Circumstance Marches' (the source of 'Land of Hope and Glory')?",o:["Ralph Vaughan Williams","Edward Elgar","Benjamin Britten","Henry Purcell"],a:1,exp:"Sir Edward Elgar (1857--1934) composed the 'Pomp and Circumstance Marches'. The first march's trio melody became 'Land of Hope and Glory', sung at the Last Night of the Proms."},

// GOVERNMENT & LAW (expansion)
{cat:"Government & Law",q:"How many MPs are there in the House of Commons?",o:["450","550","650","750"],a:2,exp:"The House of Commons currently has 650 MPs, each elected to represent a constituency."},
{cat:"Government & Law",q:"What is the Cabinet?",o:["The PM's senior advisers from the Civil Service","About 20 senior ministers chosen by the PM to head departments","The committee of opposition shadow ministers","The monarch's personal household staff"],a:1,exp:"The Cabinet is a group of about 20 senior MPs (and sometimes peers) chosen by the PM to head major government departments and make collective decisions on policy."},
{cat:"Government & Law",q:"What is the role of party 'whips'?",o:["MPs who scrutinise government spending","MPs who make sure colleagues attend and vote with their party","Civil servants who maintain Parliament's records","Officials who count votes in general elections"],a:1,exp:"Whips are MPs (or peers) appointed by parties to ensure colleagues attend Parliament and vote in line with the party. The Chief Whip is a senior figure in party leadership."},
{cat:"Government & Law",q:"What is the Shadow Cabinet?",o:["Senior civil servants who advise ministers","The opposition's senior team mirroring government posts","A secret committee advising the monarch","Backbench MPs who do not hold any office"],a:1,exp:"The Shadow Cabinet is the senior team of the main opposition party. Each shadow minister mirrors a government minister and scrutinises their work."},
{cat:"Government & Law",q:"What does the Scottish Parliament have power over?",o:["Defence and foreign affairs","Devolved matters including health, education and justice","Setting UK income tax rates only","Immigration and citizenship policy"],a:1,exp:"The Scottish Parliament has power over devolved matters including health, education, justice, environment and some taxes. Reserved matters (defence, foreign affairs, immigration) remain with Westminster."},
{cat:"Government & Law",q:"What is the difference between solicitors and barristers?",o:["Solicitors only handle criminal cases","Solicitors advise clients; barristers represent them in higher courts","Barristers only deal with paperwork","There is no legal difference between them"],a:1,exp:"Solicitors generally advise clients and prepare cases. Barristers specialise in advocacy and represent clients in higher courts. The distinction has been eroded as solicitors gain rights of audience."},
{cat:"Government & Law",q:"What does a magistrates' court deal with?",o:["The most serious criminal cases","Less serious crimes and preliminary hearings","Only civil disputes between businesses","Constitutional and human rights cases"],a:1,exp:"Magistrates' courts deal with less serious criminal cases (around 95% of criminal cases) and preliminary hearings of more serious cases before they go to Crown Court. Magistrates are usually unpaid volunteers."},
{cat:"Government & Law",q:"What is the Human Rights Act 1998?",o:["A law banning discrimination in employment","A law incorporating the European Convention on Human Rights into UK law","A treaty signed by the UK and the United States","A constitution for the United Kingdom"],a:1,exp:"The Human Rights Act 1998 incorporates the European Convention on Human Rights into UK law, allowing people to bring rights cases in UK courts rather than only in Strasbourg."},
{cat:"Government & Law",q:"What is 'common law'?",o:["Laws passed by Parliament only","Law developed by judges through court decisions","Laws agreed by the European Union","Local council bylaws"],a:1,exp:"Common law is law developed by judges through decisions in cases, building up precedents over centuries. It complements statute law (Acts of Parliament) and is a foundation of the UK legal system."},
{cat:"Government & Law",q:"What is the role of the police in the UK?",o:["Prosecuting criminals in court","Preventing and detecting crime, keeping public order","Sentencing those found guilty of crimes","Drafting and enforcing local council bylaws"],a:1,exp:"The police prevent and detect crime, keep public order and protect the public. Prosecution decisions are taken by the Crown Prosecution Service, and sentencing is the courts' responsibility."},
{cat:"Government & Law",q:"What body handles complaints against police in England and Wales?",o:["The Independent Office for Police Conduct (IOPC)","The Crown Prosecution Service","The Home Office Inspectorate","The Police Federation"],a:0,exp:"The Independent Office for Police Conduct (IOPC) — formerly the IPCC — investigates serious complaints and incidents involving police in England and Wales."},
{cat:"Government & Law",q:"What is a Police and Crime Commissioner (PCC)?",o:["The head of the Crown Prosecution Service","An elected official who holds local police forces to account","A senior police officer in charge of a constabulary","A judge specialising in criminal cases"],a:1,exp:"PCCs are elected officials in England and Wales who set police priorities, hold chief constables to account and oversee budgets. They are elected every four years."},
{cat:"Government & Law",q:"What is a 'green paper'?",o:["A document setting out enacted government laws","A consultation document presenting policy proposals","A budget document published with green covers","A confidential briefing for senior civil servants"],a:1,exp:"A green paper is a government consultation document outlining proposals and inviting views. A white paper is a more detailed statement of policy, often a precursor to legislation."},
{cat:"Government & Law",q:"How are members of the House of Lords selected?",o:["Elected by the public every five years","Mostly appointed (life peers); some hereditary peers and bishops","Chosen by the Prime Minister alone","Selected by lottery from registered voters"],a:1,exp:"The House of Lords mostly comprises appointed life peers, plus 92 hereditary peers and 26 Church of England bishops. Members are not elected."},
{cat:"Government & Law",q:"What is the Civil Service's relationship to the government?",o:["Civil servants set government policy","Civil servants implement government policy impartially","Civil servants are elected by the public","Civil servants direct ministers' decisions"],a:1,exp:"The Civil Service is politically neutral and implements policy on behalf of whichever government is in power. Civil servants serve successive governments of any party."},
{cat:"Government & Law",q:"How often must local council elections be held in England?",o:["Every year","At least every 4 years","Every 7 years","Only when the council collapses"],a:1,exp:"Local council elections in England are held at least every 4 years. Some councils elect all members at once; others elect a portion each year ('elections by thirds')."},
{cat:"Government & Law",q:"What is 'habeas corpus'?",o:["A right to challenge unlawful detention before a court","The right to vote in elections","The right to receive a fair wage","A medieval system of trial by combat"],a:0,exp:"Habeas corpus (Latin: 'you shall have the body') is the principle that a person cannot be detained without lawful cause. Anyone detained can demand to be brought before a court for the legality to be tested."},
{cat:"Government & Law",q:"What is the role of the monarch in UK government today?",o:["Holds executive power and runs government","Plays a constitutional, ceremonial role","Approves all judicial decisions personally","Sets the country's annual budget"],a:1,exp:"The monarch has a constitutional, largely ceremonial role: opening Parliament, granting Royal Assent, appointing the PM, and acting as head of state. Real political power lies with the elected government."},

// NATIONS & SYMBOLS (expansion)
{cat:"Nations & Symbols",q:"Which countries make up the United Kingdom?",o:["England, Scotland, Wales and Northern Ireland","England, Scotland and Wales only","Britain, Ireland and the Channel Islands","England, Scotland, Wales and the Republic of Ireland"],a:0,exp:"The United Kingdom comprises four countries: England, Scotland, Wales and Northern Ireland. The Republic of Ireland is a separate, independent state."},
{cat:"Nations & Symbols",q:"What is the Giant's Causeway?",o:["A coastal rock formation in Northern Ireland","A bridge linking Wales to Ireland","A mountain pass in the Scottish Highlands","A medieval earthwork in Cornwall"],a:0,exp:"The Giant's Causeway, on the north coast of Northern Ireland, is a UNESCO World Heritage Site. It comprises about 40,000 hexagonal basalt columns formed by ancient volcanic activity."},
{cat:"Nations & Symbols",q:"What is the Tower of London?",o:["A modern London skyscraper","A historic castle and home of the Crown Jewels","An office building used by the UK government","A clock tower at the Palace of Westminster"],a:1,exp:"The Tower of London, founded by William the Conqueror, has served as a royal palace, prison and fortress. It now houses the Crown Jewels and is one of the UK's most visited attractions."},
{cat:"Nations & Symbols",q:"What is 'Big Ben'?",o:["The clock tower next to Parliament","The great bell inside the Elizabeth Tower at Parliament","Buckingham Palace's main bell","The bell at St Paul's Cathedral"],a:1,exp:"Big Ben is the nickname of the great bell inside the Elizabeth Tower at the Palace of Westminster. The name is often (incorrectly) used for the tower itself."},
{cat:"Nations & Symbols",q:"What is Snowdonia?",o:["A region of mountains and national park in north Wales","A ski resort in the Scottish Highlands","A nature reserve in northern England","An island off the coast of Northern Ireland"],a:0,exp:"Snowdonia (Eryri in Welsh) is a national park in north Wales, home to Snowdon (Yr Wyddfa), the highest mountain in Wales. It is popular with hikers and climbers."},
{cat:"Nations & Symbols",q:"What is the Lake District?",o:["A large national park in northwest England","A region of low-lying lakes in East Anglia","A coastal area of southern Wales","An area of central Scotland"],a:0,exp:"The Lake District in Cumbria, northwest England, is a national park and UNESCO World Heritage Site. It is England's most-visited national park, known for its lakes, mountains and literary associations (Wordsworth, Beatrix Potter)."},
{cat:"Nations & Symbols",q:"What is the currency of the UK?",o:["The Euro","The pound sterling","The shilling","The British dollar"],a:1,exp:"The UK currency is the pound sterling (£), divided into 100 pence (p). Notes come in £5, £10, £20 and £50 denominations. Scottish and Northern Irish banks issue their own notes."},
{cat:"Nations & Symbols",q:"What is the UK national anthem?",o:["'Land of Hope and Glory'","'God Save the King' (or Queen)","'Jerusalem'","'Rule, Britannia!'"],a:1,exp:"The UK national anthem is 'God Save the King' (or 'God Save the Queen' under a queen). It dates from the 18th century and is sung at official events."},
{cat:"Nations & Symbols",q:"What is the Welsh-language name for Wales?",o:["Eire","Alba","Cymru","Kernow"],a:2,exp:"Cymru is the Welsh name for Wales. The Welsh language (Cymraeg) is an official language in Wales. ('Eire' is Ireland; 'Alba' is Scotland; 'Kernow' is Cornwall.)"},
{cat:"Nations & Symbols",q:"What is the official Welsh-language status alongside English in Wales?",o:["Welsh has no official status in Wales","Welsh has equal status with English in public bodies","Welsh is used only in churches and schools","Welsh is recognised but only spoken privately"],a:1,exp:"The Welsh Language Act 1993 gave Welsh equal status with English in public bodies. Around 30% of Welsh people speak Welsh, and bilingual signage is standard."},
{cat:"Nations & Symbols",q:"Where is Stonehenge located?",o:["Cornwall","Wiltshire","Yorkshire","Norfolk"],a:1,exp:"Stonehenge stands on Salisbury Plain in Wiltshire, southwest England. The prehistoric stone circle, built around 2500 BC, is a UNESCO World Heritage Site."},
{cat:"Nations & Symbols",q:"What is the highest mountain in Wales?",o:["Ben Nevis","Snowdon (Yr Wyddfa)","Scafell Pike","Cadair Idris"],a:1,exp:"Snowdon (Yr Wyddfa, 1,085m) is the highest mountain in Wales, located in Snowdonia National Park. It is climbed by hundreds of thousands of visitors each year."},
{cat:"Nations & Symbols",q:"What is the Last Night of the Proms?",o:["A New Year's Eve celebration in Edinburgh","The closing concert of the BBC Proms classical season","A Welsh harp festival held each summer","The final concert of the Edinburgh Fringe"],a:1,exp:"The Last Night of the Proms is the famous final concert of the BBC Proms at the Royal Albert Hall. It features patriotic favourites including 'Land of Hope and Glory', 'Jerusalem' and 'Rule, Britannia!'."},
{cat:"Nations & Symbols",q:"What is found at Land's End?",o:["The southwesternmost point of mainland Britain (Cornwall)","The northernmost point of mainland Scotland","The westernmost point of Northern Ireland","The easternmost point of England"],a:0,exp:"Land's End is the most southwesterly point of mainland Britain, in Cornwall. The traditional 'Land's End to John o' Groats' route runs from there to the most northeasterly point in Scotland."},
{cat:"Nations & Symbols",q:"What is John o' Groats?",o:["A point on the Welsh coast","A village near the northeasternmost tip of mainland Britain","An island off the coast of Northern Ireland","A famous Scottish whisky distillery"],a:1,exp:"John o' Groats, in the Scottish Highlands, lies near Britain's most northeasterly point. It is traditionally paired with Land's End (Cornwall) as the start/end of the longest journey on the British mainland."},

// EVERYDAY LIFE (expansion)
{cat:"Everyday Life",q:"At what age do children typically start primary school in England?",o:["Age 4","Age 5","Age 6","Age 7"],a:1,exp:"Children in England usually start primary school at age 4 or 5 in Reception class. Compulsory schooling begins from age 5. Primary school runs to age 11."},
{cat:"Everyday Life",q:"How long does secondary school education usually last in England?",o:["Ages 11 to 16","Ages 11 to 18","Ages 13 to 18","Ages 5 to 16"],a:0,exp:"Secondary school in England runs from age 11 to 16, ending with GCSEs. Students may then continue to sixth form or college (16--18) for A-levels or other qualifications."},
{cat:"Everyday Life",q:"What are 'apprenticeships'?",o:["Volunteer placements with charities","Paid work combined with on-the-job training and qualifications","Unpaid internships for graduates","Compulsory training for unemployed adults"],a:1,exp:"Apprenticeships combine paid employment with training, leading to a recognised qualification. They are available in many sectors and at multiple levels including degree apprenticeships."},
{cat:"Everyday Life",q:"In England, do you usually pay for NHS prescriptions?",o:["Yes — a flat charge applies for most adults","No — they are always free in England","Only if your income is above £50,000","Only for over-the-counter medicines"],a:0,exp:"In England, most adults pay a flat NHS prescription charge. Some groups (under 16, over 60, pregnant, on certain benefits) are exempt. Prescriptions are free in Scotland, Wales and Northern Ireland."},
{cat:"Everyday Life",q:"What is the MOT test?",o:["A school exit test for 16-year-olds","An annual roadworthiness test for vehicles over 3 years old","A medical test for new drivers","A monthly tax payment for car owners"],a:1,exp:"The MOT (Ministry of Transport) test is an annual safety and roadworthiness check for cars and most vehicles over 3 years old. Driving without a valid MOT is illegal."},
{cat:"Everyday Life",q:"Is car insurance compulsory in the UK?",o:["No — it is recommended but optional","Yes — at least third-party insurance is legally required","Only for drivers under 25","Only for new drivers within their first year"],a:1,exp:"All UK drivers must have at least third-party insurance to drive on public roads. Driving without insurance is a criminal offence and can lead to fines and a driving ban."},
{cat:"Everyday Life",q:"What is a 'tenancy agreement'?",o:["A document allowing you to buy a property","A contract between landlord and tenant for renting","A government grant for first-time renters","A type of mortgage agreement"],a:1,exp:"A tenancy agreement is a legal contract between landlord and tenant covering rent, deposit, length of tenancy and responsibilities. Most UK rentals use Assured Shorthold Tenancies."},
{cat:"Everyday Life",q:"What does a UK TV licence cover?",o:["Owning any TV set, regardless of use","Watching live TV broadcasts or BBC iPlayer","Only satellite or cable subscriptions","Only businesses showing TV publicly"],a:1,exp:"A TV licence is required to watch or record live TV broadcasts (any channel) or to use BBC iPlayer. Watching only on-demand services such as Netflix does not require a licence."},
{cat:"Everyday Life",q:"What is the legal drinking age in licensed premises in the UK?",o:["16","18","21","No legal age"],a:1,exp:"The legal drinking age in licensed premises is 18 (with limited exceptions for 16/17-year-olds eating a meal with an adult). It is illegal to buy alcohol for under-18s."},
{cat:"Everyday Life",q:"What is the upper age limit for jury service in the UK?",o:["60","70","75","No upper limit"],a:1,exp:"Jury service in the UK is open to those aged 18--70 who are on the electoral roll. The upper limit was raised from 70 to 75 in some jurisdictions but the Life in the UK handbook references age 70."},
{cat:"Everyday Life",q:"What is council tax based on?",o:["Your annual income from work","The estimated value band of your home","The number of people living in the property","Whether you own or rent the property"],a:1,exp:"Council tax is set on the basis of property value bands (A--H in England). Discounts apply for single occupants (25% off) and full-time students (often exempt)."},
{cat:"Everyday Life",q:"What is the National Minimum Wage?",o:["A recommended pay rate for new starters","The legal minimum hourly pay rate for workers","A weekly benefit for low-income families","The average wage for unskilled work"],a:1,exp:"The National Minimum Wage is the legal minimum hourly pay set by government, varying by age. The 'National Living Wage' is the higher rate for workers aged 23 and over."},
{cat:"Everyday Life",q:"What number do you call for genuine emergencies in the UK?",o:["111","999","101","123"],a:1,exp:"999 (or 112) is the UK emergency number, for police, fire, ambulance, coastguard or mountain rescue. Use it only for genuine, immediate emergencies."},
{cat:"Everyday Life",q:"What does PAYE stand for?",o:["Public Administration of Yearly Earnings","Pay As You Earn — income tax deducted by employers","Personal Allowance Yearly Exemption","Pension and Yearly Earnings record"],a:1,exp:"PAYE (Pay As You Earn) is the system by which employers deduct income tax and National Insurance from employees' wages and pay it directly to HMRC."},
{cat:"Everyday Life",q:"How are most NHS specialist appointments accessed?",o:["Patients book directly with hospital specialists","GPs refer patients to specialists when needed","Specialists are accessed only privately","Referrals must be approved by an MP"],a:1,exp:"In most cases, your GP refers you to a specialist (consultant) for hospital-based care. The GP is the gatekeeper of NHS services. Emergency care does not require referral."},
{cat:"Everyday Life",q:"What does 'A&E' stand for in the NHS?",o:["Accident and Emergency","Adult and Elderly","Antibiotics and Examination","Allergies and Eczema"],a:0,exp:"A&E (Accident and Emergency, also called Emergency Department) provides urgent care for serious injuries and life-threatening conditions, available 24/7 at major hospitals."},
{cat:"Everyday Life",q:"What is the role of a GP (General Practitioner)?",o:["A hospital surgeon performing operations","A community-based doctor providing primary care","A government adviser on public health policy","A pharmacist licensed to prescribe medication"],a:1,exp:"GPs are community-based doctors providing primary care. They diagnose and treat common conditions, prescribe medication, and refer patients to specialists when needed. Most NHS care begins with a GP."},
{cat:"Everyday Life",q:"What is Universal Credit?",o:["A free banking service offered by all UK banks","A means-tested benefit replacing several older benefits","A government-issued credit card for low-income people","A scheme to help businesses pay employees"],a:1,exp:"Universal Credit is a means-tested benefit for working-age people on low incomes or out of work. It replaces six older benefits including Jobseeker's Allowance, Housing Benefit and Working Tax Credit."},

// UK & WORLD (expansion)
{cat:"UK & World",q:"What is the European Convention on Human Rights (ECHR)?",o:["A treaty drafted by the European Union","A treaty of the Council of Europe protecting human rights","A UK-only law passed in 1998","A trade agreement between European countries"],a:1,exp:"The ECHR is a treaty of the Council of Europe (separate from the EU) signed in 1950. The UK helped draft it. It is enforced by the European Court of Human Rights in Strasbourg."},
{cat:"UK & World",q:"What is the Council of Europe?",o:["The same body as the European Union","A pan-European body promoting human rights and democracy","A military alliance of European states","An EU law-making body"],a:1,exp:"The Council of Europe is an international organisation promoting democracy, human rights and the rule of law. It has 46 member states and is separate from the EU. It oversees the ECHR."},
{cat:"UK & World",q:"What is the World Health Organization (WHO)?",o:["A UK-only public health body","A UN agency coordinating global public health","A trade body of pharmaceutical companies","A private medical research charity"],a:1,exp:"The WHO is a specialised agency of the United Nations responsible for international public health. The UK is a member and contributor."},
{cat:"UK & World",q:"What is the World Trade Organization (WTO)?",o:["A UN body regulating workers' rights","An international body regulating world trade rules","A UK regulator of foreign businesses","An EU institution overseeing exports"],a:1,exp:"The WTO regulates international trade between nations, providing a framework of rules and a forum for resolving trade disputes. The UK is a member."},
{cat:"UK & World",q:"What was the Empire Windrush?",o:["A 19th-century British warship","A ship that brought Caribbean migrants to the UK in 1948","A British exploration vessel of the 1700s","A Royal Navy submarine of the Cold War"],a:1,exp:"The Empire Windrush arrived at Tilbury in 1948 carrying around 500 Caribbean migrants invited to help rebuild post-war Britain. The 'Windrush generation' became symbolic of post-war Commonwealth migration to the UK."},
{cat:"UK & World",q:"What was the Falklands War?",o:["A 1956 conflict over the Suez Canal","A 1982 conflict between the UK and Argentina","A 1991 war over Iraq's invasion of Kuwait","A 1999 NATO action in former Yugoslavia"],a:1,exp:"The Falklands War (April--June 1982) followed Argentina's invasion of the British Falkland Islands. UK forces, led by PM Margaret Thatcher, recaptured the islands."},
{cat:"UK & World",q:"What was the Suez Crisis (1956)?",o:["A failed UK/French/Israeli intervention in Egypt over the Suez Canal","A Cold War nuclear standoff between the UK and the Soviet Union","A trade dispute between the UK and the Commonwealth","A Middle Eastern oil embargo against the UK"],a:0,exp:"The Suez Crisis (1956) saw the UK, France and Israel invade Egypt after Egyptian president Nasser nationalised the Suez Canal. US and UN pressure forced withdrawal — a humiliation that signalled the end of the UK's status as a global imperial power."},
{cat:"UK & World",q:"Who succeeded Queen Elizabeth II as monarch in 2022?",o:["Prince William","King Charles III","Prince Harry","King George VII"],a:1,exp:"King Charles III succeeded his mother, Queen Elizabeth II, on her death in September 2022. His coronation took place at Westminster Abbey in May 2023."},
{cat:"UK & World",q:"What is decolonisation?",o:["The colonisation of new lands by Britain","The process by which colonies became independent nations","The removal of British people from foreign countries","A 19th-century British exploration policy"],a:1,exp:"Decolonisation refers to the process by which colonies, especially British ones, became independent nations — accelerating after WWII. India became independent in 1947, followed by many African and Asian nations through the 1950s--70s."},
{cat:"UK & World",q:"What are the Five Eyes?",o:["A British intelligence training programme","An intelligence-sharing alliance of UK, US, Canada, Australia, NZ","A UK-only network of surveillance bodies","An EU intelligence-sharing arrangement"],a:1,exp:"The Five Eyes is an intelligence-sharing alliance of the UK, US, Canada, Australia and New Zealand. It dates from WWII and the post-war UKUSA Agreement."},
{cat:"UK & World",q:"What is the Commonwealth Games?",o:["An Olympic Games held only in London","A multi-sport event for Commonwealth nations","A UK-only annual athletics meeting","A historical sporting tradition no longer held"],a:1,exp:"The Commonwealth Games is a multi-sport event held every four years for athletes of Commonwealth countries. The UK has hosted multiple Games (most recently Birmingham 2022)."},
{cat:"UK & World",q:"Who was Sir Walter Raleigh?",o:["A medieval English king","An Elizabethan explorer and writer","A Victorian-era explorer of Africa","An 18th-century admiral and naval reformer"],a:1,exp:"Sir Walter Raleigh (c.1552--1618) was an Elizabethan explorer, writer and courtier. He helped establish English colonies in North America and is associated with introducing tobacco to England."},
{cat:"UK & World",q:"What was the Cold War?",o:["A military conflict between the UK and Russia in the 1800s","A period of tension between Western and Soviet blocs (c.1947--1991)","A rivalry between the UK and France in the 19th century","An EU dispute over fishing rights with Iceland"],a:1,exp:"The Cold War (c.1947--1991) was a period of geopolitical tension between Western powers (led by the US, including the UK) and the Soviet bloc. It included proxy wars, an arms race and intelligence rivalries, but no direct large-scale conflict."},
{cat:"UK & World",q:"What is the British Council?",o:["The national local government organisation","A body promoting British culture and English worldwide","A government department for trade with the EU","A House of Commons select committee"],a:1,exp:"The British Council is a UK organisation promoting cultural and educational opportunities internationally. It teaches English, runs cultural exchange programmes and administers UK exams abroad."},
{cat:"UK & World",q:"Who was Mahatma Gandhi (in connection with British history)?",o:["A British colonial governor of India","An Indian leader who campaigned non-violently for independence","A British prime minister of the 1940s","An Indian-born British military officer"],a:1,exp:"Mahatma Gandhi led the Indian independence movement against British rule, using non-violent civil disobedience. India gained independence from Britain in 1947."},
{cat:"UK & World",q:"What was the British Empire at its height?",o:["The largest empire in history, covering about a quarter of the globe","An empire confined to Europe and the Mediterranean","Smaller than the contemporary French and Spanish empires","Limited to the Indian subcontinent"],a:0,exp:"At its height in the early 20th century, the British Empire covered around a quarter of the world's land area and population — the largest empire in history. Most colonies became independent during the 20th century."},
];
